// 鹿港天后宮一百籤（100 首，官方線上求籤定本＋同系統補等第）。
// 此檔由 scripts/build-content.mjs 從 content-raw/ 生成，勿手改——改 content-raw 後重跑 npm run content。
export const lukangLots: Lot[] = [
  {"id":1,"name":"","level":"上","poem":["曉日曈曈萬象融","河清海晏慶年豐","生逢盛世真歡樂","好把心田答化工"],"traditional":"","official":{"功名":"水到渠成，扶搖直上","行人":"相逢知己，近在眼前","婚姻":"天定良緣，夫榮子貴","官司":"貴人扶持，有理者勝","丁口":"喜信頻來，合家吉慶","生意":"動作有利，一本萬利","疾病":"枯木逢春，欣欣向榮","出行":"順風揚帆，利有攸往","失物":"重尋有獲，只在東南","田畜":"田園多利，生息繁榮"},"modern":"這支籤描繪旭日初升、萬象和融、河清海晏的豐年景象，一片太平盛世的氣息，所求之事大多能順利開展。籤詩末句提醒：身在好運之中，記得心存感恩、多行善事，把福氣回饋出去，好運才留得住。","categories":{"愛情婚姻":"姻緣天定、感情融洽，單身者有望遇到好對象，已有伴侶者關係穩固、家庭和樂。","事業工作":"水到渠成、扶搖直上，正是放手發揮的時候，你的努力會被看見。","財運":"動則有利，經營投資都有不錯的回報，但別因順手而躁進。","健康":"如枯木逢春，身體狀況正在好轉，保持規律作息便能維持元氣。","考試學業":"準備到位，成果自然浮現，維持原本的步調應試，可望順利。","訴訟糾紛":"有貴人相助，站得住理的一方能得到公道，以和為貴更好。","失物行人":"失物往東南方向找，尋回機會大；等待的人近在眼前，很快有消息。"}},
  {"id":2,"name":"","level":"中上","poem":["臣報君恩子報親","五倫無愧感神明","一帆順境憑君去","災難消除福祿生"],"traditional":"","official":{"功名":"臘盡梅開，到時及第","行人":"燈花報喜，好音自來","婚姻":"夫妻和順，合生貴子","官司":"諸事順理，自然亨通","丁口":"平安為福，長幼咸宜","生意":"所求安分，自有大利","疾病":"如魚得水，勿藥有喜","出行":"有志四方，無往不利","失物":"隱而復現，何必擔心","田畜":"生育茂盛，災障消除"},"modern":"籤詩講的是盡忠盡孝、對得起五倫本分，連神明都有所感；只要問心無愧，前路便一帆風順，災難消退、福祿自來。核心提醒是：先把自己的本分做好，好運自然跟著來，不必外求。","categories":{"愛情婚姻":"夫妻和順、家庭圓滿，用心經營彼此的關係，感情會愈來愈穩。","事業工作":"像寒冬將盡、梅花將開，時機到了自然有成，穩穩做好眼前的事就對了。","財運":"安分經營反而有大利，不必追逐投機，正財穩健。","健康":"如魚得水，不必太擔心，小毛病不藥而癒，維持好習慣即可。","考試學業":"臘盡梅開、到時及第，持續累積實力，考期一到便能開花結果。","訴訟糾紛":"諸事順理，站在道理這一邊自然亨通，不必過度憂心。","失物行人":"失物只是暫時隱沒，會再出現，不必擔心；遠方的人捎來好消息的日子不遠。"}},
  {"id":3,"name":"","level":"上上","poem":["前生結下好姻緣","今日相逢赤線牽","多福多男並多壽","閤門喜慶此為先"],"traditional":"","official":{"功名":"福祿富足，名利兼收","行人":"薰風南來，遇我好友","婚姻":"如係遠方，更多吉利","官司":"貴人有緣，自能得意","丁口":"門庭春暖，眷屬平安","生意":"財臨午運，南方更利","疾病":"日行丙丁，災厄盡釋","出行":"出門有喜，水陸皆順","失物":"去而復來，求之不遠","田畜":"春生夏長，田財豐足"},"modern":"這是支上上籤：前世結好緣、今日紅線牽，多福多壽又闔家喜慶，尤其利於姻緣與家庭之事。提醒是：好緣分來時要好好珍惜把握，也別忘了與家人分享這份喜氣。","categories":{"愛情婚姻":"天賜良緣、紅線已牽，單身者有望遇到命中的對象，遠方來的緣分更佳。","事業工作":"名利兼收、貴人有緣，往南方發展或在夏季前後行動更順。","財運":"財運正旺，南方或夏天時節更有利，可以積極一些。","健康":"災厄漸消，一切往好的方向走，安心調養即可。","考試學業":"福祿俱足、名利雙收，考運正旺，好好發揮便是。","訴訟糾紛":"有貴人相助，能夠順利化解，結果對你有利。","失物行人":"失物去而復返，就在不遠處；出門的人一路平安，會帶著好消息回來。"}},
  {"id":4,"name":"","level":"上","poem":["喜逢春令雨霑濡","草木萌芽正及時","志士經營皆得意","農夫多黍女多絲"],"traditional":"","official":{"功名":"福祿亨通，求名及時","行人":"故人千里，遇合一朝","婚姻":"勤儉作家，枝葉茂盛","官司":"貴人恩庇，決勝無疑","丁口":"咸亨是占，家人有慶","生意":"正行財運，動作得利","疾病":"調和元氣，疾厄漸消","出行":"得見大人，所謀必合","失物":"尋覓及時，定可追回","田畜":"雞犬桑麻，熙然自足"},"modern":"春雨及時滋潤大地、草木正在萌芽，有志者經營得意、農家豐收，一切都落在對的時間點上。這支籤的重點是「及時」：時機正好，該做的事現在就動手，勤勞耕耘必有收成。","categories":{"愛情婚姻":"勤儉持家、感情紮實，兩人一起打拚，家庭會像枝葉一樣愈來愈茂盛。","事業工作":"正走財運，行動就有收穫，計畫別再拖延，把握這波好時機。","財運":"正財運旺，踏實經營的收入穩定成長，一分耕耘一分收穫。","健康":"調養元氣、病痛漸消，趁狀態好時養成好習慣，底子會更穩。","考試學業":"求名及時，正是報考、進修的好時機，下的功夫都有回報。","訴訟糾紛":"有貴人庇蔭，勝算在握，但仍以講理為先，不必咄咄逼人。","失物行人":"失物要趁早找，及時尋覓可以追回；故人千里相逢，重聚有望。"}},
  {"id":5,"name":"","level":"上","poem":["卻喜東風一夜催","萬花萬卉各爭開","黃金台上逢知已","酌酒看花意氣恢"],"traditional":"","official":{"功名":"喜遇知音，功名特達","行人":"春風消息，遇合不遠","婚姻":"媒人得力，主獲妻財","官司":"吉人天相，自有好音","丁口":"春色盈門，主人康安","生意":"枯木逢春，萌芽叢開","疾病":"宿疾漸好，逢庚即癒","出行":"走馬看花，春風得意","失物":"所失甚微，不必留意","田畜":"庶類蕃茂，更勝舊年"},"modern":"一夜東風催開百花，又在黃金台上遇見知己，把酒賞花、意氣風發——這是逢貴人、遇知音的好籤。提醒是：好機會常常藉「人」而來，多與人交流、珍惜賞識你的人，運勢會開得更快。","categories":{"愛情婚姻":"有媒人或朋友牽線特別有力，經人介紹的緣分值得認真看待。","事業工作":"喜遇知音，會有賞識你的人拉你一把，該表現自己時不用客氣。","財運":"如枯木逢春、生機萌發，財運回暖，新的機會正冒出來。","健康":"舊疾漸漸好轉，持續調養，痊癒指日可待。","考試學業":"功名特達，考運與貴人運都好，遇到好老師或好同伴助力更大。","訴訟糾紛":"吉人天相，自有好消息，不必過度擔憂。","失物行人":"遺失的東西價值不大，不必掛心；等待的人春天前後便有消息，相會不遠。"}},
  {"id":6,"name":"","level":"中","poem":["造物由來總好生","君今求我話分明","西風凜冽東風暖","自把存心仔細評"],"traditional":"","official":{"功名":"若問前途，先求自已","行人":"音信遲滯，且待開春","婚姻":"凜燠靡常，行止自主","官司":"忍耐為佳，爭競何益","丁口":"存心行善，自能安吉","生意":"安份守舊，不必妄想","疾病":"病體多變，調攝無方","出行":"東去方宜，西方失利","失物":"運當小耗，須防失脫","田畜":"小限落空，孳息小利"},"modern":"上天有好生之德，但西風凜冽、東風和暖，冷暖如何全看你自己怎麼存心、怎麼選擇。這支籤把答案交回你手上：先靜下來，誠實檢視自己的起心動念，路自然會清楚。","categories":{"愛情婚姻":"感情冷暖自知，去留進退由你作主，先想清楚自己要什麼再做決定。","事業工作":"前途如何先問自己，目前以安分守成為宜，不急著擴張或跳動。","財運":"守舊安分即可，不必妄想快錢，穩住現有的比較實在。","健康":"身體狀況起伏較多，調養要有耐心，別亂試偏方，找對方法慢慢來。","考試學業":"成績取決於自己下的功夫，與其問運氣，不如檢視讀書方法。","訴訟糾紛":"忍耐為佳，爭到底未必有益，能退一步就退一步。","失物行人":"近期留意隨身財物，防止失落；等待的人音訊較慢，可能要等到開春。"}},
  {"id":7,"name":"","level":"中下","poem":["滿目風雲咫尺迷","胡為惘惘欲何之","不如急把船頭轉","省得狂波破膽時"],"traditional":"","official":{"功名":"人不知命，求榮反辱","行人":"思君不見，天各一方","婚姻":"到底不佳，還宜別就","官司":"兩虎相門，必有一傷","丁口":"眷屬有憂，不如歸去","生意":"時運未通，營求無益","疾病":"及早祈禱，危而得安","出行":"風波險窄，無處渡河","失物":"運當失財，庶免餘悔","田畜":"生息稀少，切莫貪心"},"modern":"眼前風雲密布、咫尺難辨，籤詩勸你別再茫茫然往前衝，不如趕快把船頭調轉，免得被狂浪嚇破膽。這是支提醒「回頭、收手」的籤：現在不是前進的時機，及早調整方向就能避開風險。","categories":{"愛情婚姻":"這段緣分走得辛苦，若一再感到不對勁，不必勉強硬撐；緩下來重新考慮，也是善待自己。","事業工作":"時運未通，強求難有成果，先守住本業、避開新的冒險，等局勢明朗再動。","財運":"此時營求無益，別擴大投資或借貸，守住現金、減少開銷為上。","健康":"有狀況要及早處理，別拖延，儘早就醫、好好調養，危可轉安。","考試學業":"勉強求成反而受挫，不如調整目標與方法，把基礎補穩再上。","訴訟糾紛":"兩虎相鬥必有一傷，硬碰硬雙方都受害，能和解就和解，退一步海闊天空。","失物行人":"失物尋回機會不大，別太自責，就當提醒自己往後多留心；遠方的人一時音訊難通，耐心等待。"}},
  {"id":8,"name":"","level":"上上","poem":["積德如君歲十年","何須禮拜問神仙","一帆順境誰能及","利有攸往涉大川"],"traditional":"","official":{"功名":"為善必昌，功德無量","行人":"知心相遇，期在旦夕","婚姻":"夫妻和順，家室興隆","官司":"官星輔助，諸事順利","丁口":"家門清泰，人口平安","生意":"十分財氣，滿載而歸","疾病":"福星拱照，災悔全消","出行":"出門大利，永無阻礙","失物":"失物不遠，只在溪邊","田畜":"田園獲利，孳息繁昌"},"modern":"積德十年、根基深厚，根本不必求神問卜——一帆順境無人能及，正利於大展身手、渡越大川。這支籤肯定你平日的善行與累積，此刻放手去做想做的大事，唯記得莫忘初心。","categories":{"愛情婚姻":"夫妻和順、家室興隆，感情有深厚的基礎，可以放心走下一步。","事業工作":"諸事順利、有如神助，大計畫可以推進，正是「利涉大川」的時候。","財運":"十分財氣、滿載而歸，投資經營都有豐厚回報。","健康":"福星拱照，病痛災厄消退，安心休養即可。","考試學業":"平日累積深厚，應試順利，功到自然成。","訴訟糾紛":"有貴人與正理相助，諸事順利，可望圓滿落幕。","失物行人":"失物就在不遠處，往水邊、溪邊方向找找；想見的人很快便會相遇。"}},
  {"id":9,"name":"","level":"中","poem":["世事怎能獲萬全","總憑一點好心田","吉凶禍福惟人召","我本無私亦不偏"],"traditional":"","official":{"功名":"廣行陰騭，自行格天","行人":"音信迢遥，尚多阻隔","婚姻":"先憂後喜，守正則吉","官司":"事多失意，退讓為高","丁口":"勸君行善，庶保平安","生意":"存心忠厚，必獲利益","疾病":"保身之法，及早修為","出行":"安份守已，盡人待天","失物":"既往不究，且防後悔","田畜":"盈歉無定，生息平平"},"modern":"世事本難十全十美，吉凶禍福其實都是自己招來的，天地無私、不偏袒誰——一切回到那一點好心田。這支籤提醒：與其求外在的運氣，不如守住正直與善念，福氣自然慢慢聚攏。","categories":{"愛情婚姻":"先憂後喜，過程也許有些波折，只要真誠守正，感情終會走向安穩。","事業工作":"多做實事、累積口碑，路才走得長遠；急功近利反而失分。","財運":"存心忠厚、誠信經營必獲利益，賺該賺的錢最穩。","健康":"保養要趁早，平日的作息與習慣就是最好的藥方。","考試學業":"成果與付出成正比，踏實用功比求好運更有用。","訴訟糾紛":"事情多有不如意，退讓為高，能息事寧人就別戀戰。","失物行人":"失物難尋，就當破財消災，記取教訓防範下次；遠方的人音訊迢遙，還需一段時間。"}},
  {"id":10,"name":"","level":"下下","poem":["泰極否來汝不知","循環往復道無私","回思昔日風光好","卻悔今朝禱告遲"],"traditional":"","official":{"功名":"盛極當衰，不須奢望","行人":"月缺雲遮，望之不見","婚姻":"只宜安份，不必強求","官司":"官鬼相剋，事多反側","丁口":"門衰戶冷，影隻行單","生意":"草枯花謝，秋景蕭疏","疾病":"自絕於天，祈禱無益","出行":"世路崎嶇，徒勞跋涉","失物":"悖入悖出，報應不差","田畜":"雞犬蕭條，桑麻零落"},"modern":"泰極否來，運勢像四季循環，正從高處往下走；籤詩借「回想昔日風光、後悔禱告太遲」提醒你，別再留戀過去的順境。此時宜守不宜攻：收斂低調、及早調整補救，安穩度過這段低潮，循環總會再往上。","categories":{"愛情婚姻":"感情之事只宜隨緣安分，不必強求；先把自己照顧好，緣分到了自然明朗。","事業工作":"盛極當衰，不宜奢望擴張或高升，先穩住現有位置，低調做事、減少變動。","財運":"秋景蕭疏、進帳有限，避免投資擴張，量入為出、守住老本最要緊。","健康":"身體的警訊千萬別拖，及早就醫、認真調養；平日保養遠勝臨時抱佛腳。","考試學業":"這次成績可能不如預期，別灰心；放低目標、重整讀書方式，留待下回再戰。","訴訟糾紛":"事多反覆、變數不少，避免興訟，能和解就和解，減少損耗為上。","失物行人":"失物尋回不易，就當一次提醒，往後財物多上心；遠方的人如月被雲遮，一時難有消息。"}},
  {"id":11,"name":"","level":"中下","poem":["驚風駭浪失西東","一盞神燈照碧空","急向前途求解脫","上天憫惻是愚蒙"],"traditional":"","official":{"功名":"欲望榮華，須常修德","行人":"雁落魚沉，相思不見","婚姻":"既多凶險，且有反覆","官司":"多言多敗，多事多悔","丁口":"大小欠安，當祈神佑","生意":"公平交易，庶保安穩","疾病":"誠心祈禱，庶保安寧","出行":"風波四起，及早回頭","失物":"亡羊補牢，尚可得半","田畜":"須防失利，難免災侵"},"modern":"驚風駭浪中迷失了方向，幸好碧空中還有一盞神燈照路——處境雖險，上天仍憐憫指引。這支籤要你別再往風浪裡衝，趕快朝著燈的方向走：停損、回頭、安頓身心，就能脫離險境。","categories":{"愛情婚姻":"感情多有波折反覆，先穩住自己，不急著做重大決定，看清楚再走下一步。","事業工作":"想求發展，先把根基與信用顧好；此時宜穩不宜衝，誠信是你的護身符。","財運":"公平交易、老實經營才保得住安穩，投機取巧容易翻船。","健康":"大小狀況都要留意，好好休息、及早調理，誠心照顧身體，身體會給你回報。","考試學業":"心浮氣躁難有成，先靜下心修好基本功，穩住陣腳最重要。","訴訟糾紛":"多言多敗、多事多悔，話少一點、事緩一點，避免節外生枝。","失物行人":"亡羊補牢還來得及，趕快找還能挽回一部分；遠方的人音訊杳然，相見還需等待。"}},
  {"id":12,"name":"","level":"中中","poem":["汝曹逐末泛重洋","順意遊行自主張","得利須知尋退步","免教失足悔難當"],"traditional":"","official":{"功名":"成功者退，勿戀榮華","行人":"風流雲散，會少離多","婚姻":"切莫高攀，須當量力","官司":"得半則吉，求多者殃","丁口":"君子務本，先貴親親","生意":"好風得利，早理歸帆","疾病":"看破一切，謹慎保身","出行":"捨近圖遠，必有後悔","失物":"若欲求全，反更有失","田畜":"小則可望，多則有失"},"modern":"出海經商順風順水、自在得利，但籤詩話鋒一轉：得利之後要懂得找退路，見好就收，才不會失足後悔。這是支「知進退」的籤：眼前確有利可圖，重點在於適可而止。","categories":{"愛情婚姻":"對象務實相配比高攀重要，量力而為的感情才走得長久。","事業工作":"順風時更要想好退路，階段目標達成就收，功成身退，別戀棧。","財運":"有利可圖，但賺到合理的利潤就該收手，貪多容易反吐回去。","健康":"看開放下、不過度操勞，謹慎保養身體，別拿健康去換成就。","考試學業":"目標設在能力範圍內，穩紮穩打；好高騖遠反而容易失手。","訴訟糾紛":"得一半就是吉，見好就收；求全求多反招災殃。","失物行人":"別想全數找回，能尋回一部分就是萬幸；出門的人聚少離多，相會需要耐心。"}},
  {"id":13,"name":"","level":"上","poem":["天生富貴洵堪誇","畢竟相承積善家","告汝要言無別事","再能培植慶無涯"],"traditional":"","official":{"功名":"作善降祥，報施不爽","行人":"庭前鵲噪，必有好音","婚姻":"吉人天相，宜爾室家","官司":"神靈庇祐，官貴提攜","丁口":"室家安樂，人口平安","生意":"財運亨通，愈宜修德","疾病":"逢凶化吉，醫禱皆應","出行":"近悦遠來，無往不利","失物":"小往大來，不須介意","田畜":"田禾富足，庶類咸亨"},"modern":"富貴不是憑空而來，是祖上與自己積善累積的果實；籤詩交代的要事只有一件——繼續培植善根，福慶便綿延無涯。這是支好籤，提醒你在順境中更要謙虛行善，把福氣養得更深。","categories":{"愛情婚姻":"吉人天相、宜室宜家，感情與家庭都有福蔭，用心經營便能長久。","事業工作":"作善降祥、貴人提攜，事業有靠山，愈是順利愈要厚道待人。","財運":"財運亨通，行有餘力多回饋，愈懂得分享，財庫愈穩。","健康":"逢凶化吉，就醫調養都見效驗，不必過度擔心。","考試學業":"平日的累積會忠實反映在成績上，考運不差，安心應試。","訴訟糾紛":"有神明庇祐、貴人提攜，可望順利化解。","失物行人":"小失換大得，遺失的東西不必掛心；等待的人喜鵲報喜，好消息將至。"}},
  {"id":14,"name":"","level":"上中","poem":["十載窗下苦操修","今日彈冠事壯遊","萬里長風欣得意","直登彼岸不須愁"],"traditional":"","official":{"功名":"學優登仕，致君澤民","行人":"故人相逢，怡然自得","婚姻":"配合若遲，自然得意","官司":"情詞順理，貴人有緣","丁口":"家人有慶，諸事皆宜","生意":"貿易得利，風水平穩","疾病":"吉星高照，災禍不生","出行":"順風得利，動無不利","失物":"遠處尋覓，當有著落","田畜":"孳息豐盈，十分有利"},"modern":"十年寒窗苦讀，今日終於出頭，乘萬里長風壯遊四方，直登彼岸不必憂愁——這是努力到位、時機成熟的意象。這支籤告訴你：過去下的苦功即將兌現，放心大步向前。","categories":{"愛情婚姻":"緣分或許來得慢，但慢有慢的好，時候到了自然稱心如意。","事業工作":"苦盡甘來，正是大展身手的時候，升遷、轉換跑道都順。","財運":"貿易得利、進帳平穩，努力的報酬開始回收。","健康":"吉星高照、災禍不生，維持現在的好狀態即可。","考試學業":"這支籤最利考試——十載寒窗一朝得意，放膽應試，可望金榜題名。","訴訟糾紛":"情理站得住腳，又有貴人相助，結果對你有利。","失物行人":"失物可能落在較遠的地方，往遠處找會有著落；故人相逢，歡喜自得。"}},
  {"id":15,"name":"","level":"中中","poem":["種稻高原逢旱歲","插苗低畝遇雨年","欲晴不晴雨不雨","天不絕人人絕天"],"traditional":"","official":{"功名":"痴心妄想，一事無成","行人":"山外青山，煙雲縹渺","婚姻":"所望難成，成亦無濟","官司":"事多反覆，終至憂疑","丁口":"雲散風流，猿啼月落","生意":"生意索然，意興蕭條","疾病":"旱井枯魚，油燼燈暗","出行":"跋涉徒勞，一無所就","失物":"運當破耗，陰人算計","田畜":"籬落蕭條，毫無生趣"},"modern":"在高地種稻偏逢旱年、低田插秧偏遇雨年，要晴不晴、要雨不雨——凡事總與時機錯身而過。但籤詩點出關鍵：「天不絕人人絕天」，不是老天斷你的路，而是別自己先放棄；此時宜調整做法、耐心等對的時節，不宜硬拚。","categories":{"愛情婚姻":"目前的期待容易落空，強求也無益；先把自己過好，時機對了再談不遲。","事業工作":"諸事不逢時，計畫容易卡關，先縮小目標、調整方向，別跟時機硬碰硬。","財運":"進帳清淡，此時守成勝過開源，避免新的投入與開銷。","健康":"元氣偏弱，像燈油將盡需要添補——別硬撐，好好休養、及早調理，把身體放在第一位。","考試學業":"期望與現實有落差，先誠實檢視實力與方法，重新布局比硬考更實在。","訴訟糾紛":"事情反覆難定、徒增憂疑，能不興訟就不興訟，把心力留給自己。","失物行人":"近期易有破耗，財物多留心，也防他人趁隙；遠方的人如山外青山、煙雲縹緲，音訊一時難得。"}},
  {"id":16,"name":"","level":"上中","poem":["君看靈旗忽轉東","定知好事與從容","神天庇祐須思報","一炷心香帝座通"],"traditional":"","official":{"功名":"文有進益，錄運亨通","行人":"紫氣東來，幸遇故人","婚姻":"有求必成，諸事如意","官司":"貴人扶持，轉禍為福","丁口":"家室豐盈，椿萱並茂","生意":"財行震方，利息加倍","疾病":"幸逢神庇，宿疾漸癒","出行":"順水行舟，東風徐來","失物":"難中不遇，餘物清吉","田畜":"雞犬平穩，禾黍順意"},"modern":"靈旗忽然轉向東方，預示好事將從容而至；受神明庇祐之餘，記得一炷心香誠心答謝。這支籤是轉運之兆——尤其東方、東邊的機會有利，心懷感恩，好事會接連而來。","categories":{"愛情婚姻":"有求必成、諸事如意，感情進展順利，可以放心推進。","事業工作":"文書、學識相關的發展有進益，往東方或東邊的機會特別有利。","財運":"財在東方、獲利加倍，來自東邊的機會值得把握。","健康":"幸得庇祐，舊疾漸癒，持續調養就會愈來愈好。","考試學業":"文運亨通、學業有進步之象，考運正旺，好好發揮。","訴訟糾紛":"有貴人扶持，轉禍為福，可望翻轉局面。","失物行人":"遺失的這件較難尋回，但其餘財物平安無虞，放寬心；等待的人紫氣東來，有幸相逢。"}},
  {"id":17,"name":"","level":"中中","poem":["求名從此是亨衢","求利剛逢是利區","但許一心求一事","不容兩念並馳驅"],"traditional":"","official":{"功名":"所欲必遂，不可過奢","行人":"久旱得霖，相逢有日","婚姻":"見可就成，不須多慮","官司":"但能小勝，不合多求","丁口":"家書一紙，真抵萬金","生意":"喜逢財運，得意便休","疾病":"專心醫治，自可霍然","出行":"風雲際會，必有遇合","失物":"蹤跡未遇，猶可得半","田畜":"六畜平安，利可五分"},"modern":"求名正逢亨通大道、求利剛好走到得利之區，但籤詩開出條件：一次只許專心求一件事，不容兩頭兼顧。這支籤的關鍵是「專注」——選定目標全力以赴就能成，貪多分心反而兩頭空。","categories":{"愛情婚姻":"覺得合適就可以定下來，不必想東想西；專一以待，感情自然成。","事業工作":"機會就在眼前，但別同時追兩個目標，選定一條路深耕才會有成。","財運":"財運正逢，見好便收，賺到合理的利潤就該滿足。","健康":"專心治療，別一直換方法換醫生，持之以恆自可痊癒。","考試學業":"心無旁騖最重要，選定志願專心衝刺可望如願，但目標別設得太貪。","訴訟糾紛":"可得小勝，適可而止，別得理不饒人、擴大戰線。","失物行人":"失物蹤跡未明，用心找還能尋回一部分；久候的人如久旱逢甘霖，相逢有日。"}},
  {"id":18,"name":"","level":"中上","poem":["汝是懸崖一樹梅","一塵不染向春開","待看綠葉成蔭後","結子滿枝調鼎來"],"traditional":"","official":{"功名":"功名得時，更有後福","行人":"春信吹來，會合不遠","婚姻":"勿嫌清淡，可卜繁昌","官司":"立身不敗，逢凶化吉","丁口":"門楣有喜，桂馥蘭馨","生意":"財源滾滾，積厚流光","疾病":"枯木逢春，自能生發","出行":"出門順利，收成更好","失物":"謹慎把守，失小得多","田畜":"春生秋實，利息盈餘"},"modern":"你是懸崖上的一株梅，一塵不染迎著春天綻放；等綠葉成蔭之後，滿枝結子、終能擔當大任。這支籤讚許你的清白與堅持——眼前也許清淡，但根基正在成形，耐心等待，後福深厚。","categories":{"愛情婚姻":"別嫌現在平淡，這段感情底子乾淨紮實，往後會愈來愈興旺。","事業工作":"功名得時、更有後福，眼前的位置只是起點，持續累積必受重用。","財運":"財源如結子滿枝，愈積愈厚，穩健經營就有細水長流的收穫。","健康":"如枯木逢春，體力元氣漸漸回來，順勢調養即可。","考試學業":"現在的苦讀就是扎根，時候到了自然開花結果，前景可期。","訴訟糾紛":"立身正直便不敗，逢凶化吉，不必過度憂慮。","失物行人":"財物謹慎看守，失小得多、整體無礙；等待的人春信已至，相會不遠。"}},
  {"id":19,"name":"","level":"上中","poem":["渭川白頭一漁翁","遇合來時便不同","莫道迍邅心便冷","須將忍耐付窮通"],"traditional":"","official":{"功名":"大器晚成，老當益壯","行人":"知已相逢，期在歲暮","婚姻":"求媒費力，終當有成","官司":"諸事忍耐，不可便宜","丁口":"衣錦榮歸，團圓喜慶","生意":"晚運亨通，只宜堅忍","疾病":"耐煩保身，逢春即癒","出行":"守志自力，必有際遇","失物":"運犯小耗，更當謹守","田畜":"春夏小利，秋冬乃成"},"modern":"渭水邊白髮的漁翁正是姜太公，遇合的時機一到，身價便截然不同；籤詩勸你別因一時困頓就心冷，把「忍耐」放進順逆之間。這是支大器晚成的籤：你的時機在後頭，沉得住氣的人才等得到。","categories":{"愛情婚姻":"說媒、追求都要多費些力氣，但終究會修成正果，別半途而廢。","事業工作":"大器晚成、老當益壯，眼前的蹲低是為了將來的躍起，堅持下去。","財運":"晚運亨通，前期宜堅忍守成，收穫落在秋冬、在後段。","健康":"耐著性子調養，別急著求速效，時序入春便見起色。","考試學業":"這次未必立見成果，但累積不會白費；繼續熬下去，晚成的器往往更大。","訴訟糾紛":"諸事忍耐，別貪一時便宜，沉住氣對你最有利。","失物行人":"近期易有小損耗，財物更要謹慎看管；等待的人知己相逢，約在年底前後。"}},
  {"id":20,"name":"","level":"上中","poem":["制虎降龍靜煉丹","從今縱躍出玄關","前途一片風光好","不到蓬萊只等閑"],"traditional":"","official":{"功名":"苦而得甘，不負所志","行人":"音信艱難，萍踪寡合","婚姻":"逢寅遇辰，成家最利","官司":"是非可免，從此亨通","丁口":"若門家丁，從此安康","生意":"欲求利益，利得十分","疾病":"所得宿疾，從此痊癒","出行":"出門遇合，西行較勝","失物":"財物已去，何必追尋","田畜":"田財利息，當勝舊年"},"modern":"制虎降龍、靜心煉丹，如今功成縱躍而出——前途一片風光，連蓬萊仙境都不在話下。這支籤講的是苦盡甘來：長期的修煉與忍耐已經到位，接下來放膽前行，莫負初衷。","categories":{"愛情婚姻":"成家的緣分正好，時機成熟便水到渠成，可以認真規劃。","事業工作":"苦而得甘、不負所志，多年蹲點即將開花，往西邊的機會更佳。","財運":"求利可得十分，之前的投入開始回收，行動有利。","健康":"纏身的舊疾從此漸癒，最辛苦的階段已經過去。","考試學業":"苦讀有成、志向不負，放膽應試，成果會對得起你的努力。","訴訟糾紛":"是非可免、從此亨通，糾紛可望落幕，往後順遂。","失物行人":"失去的財物就別再追尋，放下才輕鬆；遠方的人音訊較難，聚散隨緣，耐心等候。"}},
  {"id":21,"name":"","level":"中","poem":["汝今行運未全通","且看春來萬象融","疾病漸瘳元氣復","自然事事稱心胸"],"traditional":"","official":{"功名":"名利多阻，運到即通","行人":"若問好音，開春可至","婚姻":"目下未利，且待來春","官司":"是非明白，不必憂慮","丁口":"春色盈門，合家清吉","生意":"目下苦守，新年乃佳","疾病":"疾厄漸消，逢春便吉","出行":"若望東行，終當有慶","失物":"謹慎小心，可無後患","田畜":"今歲未利，開春乃佳"},"modern":"這支籤說你目前的運勢還沒完全打開，就像寒冬未盡，但只要等到春天來臨，萬物回暖，病痛會慢慢痊癒、元氣恢復，事情自然一件件順心。核心提醒是：現在是過渡期，別急著硬闖，安穩撐過眼前，開春之後局面就會明顯好轉。","categories":{"愛情婚姻":"感情目前時機未到，勉強推進容易受挫；耐心等到來春，緣分自然會比較順。","事業工作":"求職升遷眼下阻礙較多，但不是沒希望，運一到就通；先把實力顧好，等時機成熟再出手。","財運":"近期財路平平，宜守不宜攻；撐過這段苦守期，新的一年生意和收入都會轉佳。","健康":"病痛正在逐漸消退，只要好好調養，等天氣回暖、春天一到就能康復。","考試學業":"目前讀書求名多有阻滯，但不代表沒實力；持續準備，運勢一開就能考出成果。","訴訟糾紛":"是非曲直終會水落石出，不必過度憂慮，靜待事情自然釐清即可。","失物行人":"等候的人若有好消息，開春可望到來；失物方面要謹慎小心處理，才不會留下後患。"}},
  {"id":22,"name":"","level":"下下","poem":["福澤從來未易求","枉勞心力費鑽謀","到頭無益徒貽笑","疾病相侵萬事休"],"traditional":"","official":{"功名":"枉費心機，求榮反辱","行人":"流落天涯，音信寥落","婚姻":"痴人妄想，到底無成","官司":"命犯官符，當有小災","丁口":"鶴望淒涼，雁聲鳴咽","生意":"勞心費力，謀求無益","疾病":"神靈不祐，醫藥徒然","出行":"背井離鄉，須防失利","失物":"陰人算計，須防失脫","田畜":"禾黍蕭條，羽毛零落"},"modern":"籤詩說福分本來就不是強求得來的，費盡心機去鑽營，到頭來不但沒有好處，還可能惹人笑話，加上病痛纏身，事情更難推進。這是一支下下籤，提醒你此刻最重要的是停下強求的腳步，先把身體和心安頓好，守住現有的，別再投入新的冒險，等狀態恢復再談其他。","categories":{"愛情婚姻":"這段感情若是一廂情願，再努力也難有結果；與其空耗，不如先放下執著，把自己照顧好。","事業工作":"眼下不宜強求升遷或轉換，費盡心力也難見成效；先穩住本分工作，養精蓄銳等待下一波機會。","財運":"投資或新生意此刻勞心費力卻難有收益，切莫加碼；守住現金、減少支出，是目前最好的理財方式。","健康":"身體是這支籤最要緊的警訊，別拖延也別只靠偏方；及早正規就醫、耐心調養，並保持心情平穩。","考試學業":"急著求表現反而容易失常；這段時間先調整身心和讀書方法，把基礎補穩，來日再拚。","訴訟糾紛":"官司恐有小的不利，能和解就和解，別戀戰；態度放低、及早收尾，損失才能降到最小。","失物行人":"出門在外的人音信稀少，需多點耐心等候；失物恐與他人有關，財物要收好，慎防再有損失。"}},
  {"id":23,"name":"","level":"中","poem":["行舟共識賴神明","椗舵當教要小心","莫到急流方著力","閒中打點免災侵"],"traditional":"","official":{"功名":"欲望榮華，須先努力","行人":"會少離多，音書稀少","婚姻":"當圖安穩，莫任攀高","官司":"諸事退讓，方為平穩","丁口":"眷口啾唧，可無大害","生意":"利息微薄，須要把握","疾病":"小心保養，庶可無虞","出行":"步步小心，平安無事","失物":"命犯破財，有小失脫","田畜":"田園荒落，孳息稀疏"},"modern":"籤詩以行船比喻人生：船要平安，除了敬天，更要平時就把舵和錨顧好，不能等到急流才臨時使力；閒時多打點，災禍自然不上身。這支籤的核心是「未雨綢繆」——現在就把該準備的準備好、該檢查的檢查好，遇到風浪才不會手忙腳亂。","categories":{"愛情婚姻":"感情宜求安穩踏實，別一味追求條件更好的對象；珍惜眼前、用心經營，反而走得長久。","事業工作":"想有一番成就，就得趁現在下功夫；平日多累積、多準備，機會來時才接得住。","財運":"獲利不會太豐厚，但只要謹慎把握、穩紮穩打，還是守得住；切忌貪快冒進。","健康":"沒有大礙，但要趁還健康時就好好保養；作息、飲食提早注意，勝過生病才補救。","考試學業":"成績靠平時累積，臨時抱佛腳最危險；及早規劃進度、按部就班，考試自然穩當。","訴訟糾紛":"凡事以退讓為上策，別逞一時之氣；能大事化小，就是最平穩的結果。","失物行人":"在外的人聚少離多、音信不多，先別過度擔心；財物近期有小失的可能，出入多留意隨身物品。"}},
  {"id":24,"name":"","level":"上中","poem":["共道今年勝舊年","家門氣象覺熙恬","勸君得隴毋望蜀","卻省中懷似火煎"],"traditional":"","official":{"功名":"得尺得寸，不可躁進","行人":"魚雁相通，可慰懸念","婚姻":"娶妻迪吉，納妾招禍","官司":"事理平穩，適可而止","丁口":"新運勝舊，平安為福","生意":"運氣漸佳，安心能守","疾病":"潮月勿藥，可保痊安","出行":"只宜步穩，不可橫行","失物":"財勿已去，悔之無益","田畜":"景象舒適，當續順遂"},"modern":"籤詩說今年運勢確實勝過往年，家中氣氛和樂安穩，是好光景；但也勸你「得隴莫望蜀」——已經到手的好處要懂得珍惜，若貪心想要更多，反而讓自己心急如焚。這支籤的核心是知足：好運正在路上，穩穩地走、不躁進，福氣才留得住。","categories":{"愛情婚姻":"正緣婚事吉利可成，用心經營現有的感情就好；三心二意、腳踏兩條船只會招來禍端。","事業工作":"運勢比之前好，能一步步往上走；但升遷發展宜循序漸進，得寸進尺反而壞事。","財運":"財運漸入佳境，安心守成就有收穫；別因小有斬獲就擴大槓桿，穩健才是這支籤的財路。","健康":"小恙不需重藥，順其自然調養，過一段時日即可痊癒安康。","考試學業":"成績會比之前進步，值得肯定；但別因此躁進跳級挑戰，把眼前的每一步走穩最重要。","訴訟糾紛":"事情大致平穩，占理也要懂得適可而止；見好就收，別把小紛爭鬧大。","失物行人":"在外的人音信可通，足以放心。失物若已失去，追悔無益，就當破財消災，往後多加留心。"}},
  {"id":25,"name":"","level":"中","poem":["臘雪消除春水生","沙灘不礙客舟行","載來貨物誇多利","須慮旁人覬覦生"],"traditional":"","official":{"功名":"前程有望，謹慎為先","行人":"春信已通，行人即到","婚姻":"須早圖謀，遲則有變","官司":"諸事順利，適可而止","丁口":"人口平安，宜防口舌","生意":"財氣頗佳，須防後變","疾病":"疾已痊癒，謹慎保身","出行":"此去慎行，須防小人","失物":"陰人暗算，尚須謹防","田畜":"利息雖好，恐有失脫"},"modern":"籤詩描繪冬雪融化、春水初生，沙灘不再擋路，船隻載著貨物順利獲利——時運已經轉開，行動可以得利；但末句提醒，賺了錢容易引來旁人眼紅覬覦。這支籤的核心是：把握眼前的好時機，同時財不露白、行事低調，才能把到手的利益守住。","categories":{"愛情婚姻":"有意的對象要及早表態、及早定案，拖久了恐怕生變；把握當下的緣分最要緊。","事業工作":"前程有望，計畫可以推進；但成果出來後別張揚，謹慎處理人際，慎防有人眼紅使絆。","財運":"財氣頗佳，正是進帳的好時候；不過獲利後要留意後續變化，落袋為安、不炫富，防人覬覦。","健康":"病已痊癒或接近康復，但別大意；持續保養身體，別因為好轉就恢復壞習慣。","考試學業":"考運正在回春，努力會有回報；保持謙虛低調，別因一次好成績鬆懈或招忌。","訴訟糾紛":"事情大致順利，但見好就收，別得理不饒人；適可而止才能真正了結。","失物行人":"遠方的人音信已通，很快就會到來或有消息。失物恐與有心人有關，財物務必收妥，加倍提防。"}},
  {"id":26,"name":"","level":"上中","poem":["旱年宜豆雨宜禾","合著天時總不差","若遇南風應買豆","今年利息十分多"],"traditional":"","official":{"功名":"命坐文昌，科名有望","行人":"消息已通，午日即到","婚姻":"姻緣可成，丙丁尤利","官司":"占多吉兆，可以無憂","丁口":"人口平安，勝於舊年","生意":"相機而行，可得大利","疾病":"南風解散，災悔消除","出行":"祿馬在午，利有攸往","失物":"物失在南，尋之必獲","田畜":"秋冬平常，入夏大利"},"modern":"籤詩用農事作比喻：旱年適合種豆、雨年適合種稻，只要配合天時就不會出錯；若遇南風就該買豆，今年獲利會非常豐厚。這是一支順天應時的好籤，核心提醒是：機會已經備好，關鍵在看準時機、順勢而為，方向對了就大膽行動。","categories":{"愛情婚姻":"姻緣可成，時機與條件都在對你有利的方向；把握合適的時點推進，好事可期。","事業工作":"運勢與才能都到位，發展大有可為；重點是看清趨勢、選對切入時機，順勢出手必有斬獲。","財運":"相機而行可得大利，尤其入夏之後財氣更旺；投資做生意要跟著時勢走，別逆勢操作。","健康":"病氣如遇南風吹散，災厄消除；天氣轉暖後身體會明顯好轉，安心調養即可。","考試學業":"文昌照命，科名有望，是利於考試的好籤；穩住步調認真準備,金榜可期。","訴訟糾紛":"多是吉兆，不必憂心；事情會往對你有利的方向發展。","失物行人":"在外的人消息已通，近日（午日前後）可望到來；失物可往南方找，用心尋必能找回。"}},
  {"id":27,"name":"","level":"中","poem":["讀書十載不成名","卻要經營往外行","涉水登山程萬里","報君好事在先庚"],"traditional":"","official":{"功名":"功名不成，改途得利","行人":"行人在途，逢庚必到","婚姻":"捨近求遠，方可有成","官司":"事和為貴，息訟遠行","丁口":"眷屬平安，秋來更好","生意":"庚辛是金，利得十分","疾病":"消遣為佳，不宜沉悶","出行":"西方大利，必有遇合","失物":"步步小心，須防失脫","田畜":"雞黍得利，且待收成"},"modern":"籤詩說十年寒窗未必換來功名，不如轉個方向、往外闖蕩經營，雖然要跋山涉水走萬里路，但好消息會在「庚」的時節（庚日或秋天）到來。這支籤的核心是「轉換跑道」：原路走不通不是你不行，而是方向該調整了；願意走出去，反而海闊天空。","categories":{"愛情婚姻":"近處的緣分不易成，眼光放遠一點，異地或不同圈子的對象反而有機會開花結果。","事業工作":"在原領域苦撐難有突破，考慮轉行、外派或往外地發展；改變路線後反而能得利。","財運":"往外經營、與金屬或西方相關的財路特別旺；秋天（庚辛）前後是獲利的好時點。","健康":"身體無大礙，但心情鬱悶對健康最傷；多出門走走、找點消遣散心，比吃藥更有效。","考試學業":"若考試屢屢不順，不必死守同一條路；換個科系、跑道或目標，天分反而能發揮。","訴訟糾紛":"以和為貴，能息訟就息訟；了結之後把心力放到遠方的新機會上，別耗在爭執裡。","失物行人":"在外的人已在路上，逢庚日可望到達。財物要步步小心看管，慎防遺失。"}},
  {"id":28,"name":"","level":"中上","poem":["天生驥足豈尋常","自幼生來骨格強","馳騁康莊無絆礙","一逢伯樂便稱良"],"traditional":"","official":{"功名":"富貴前定，必遇知音","行人":"行人在途，相逢不遠","婚姻":"幸得知心，所求必遂","官司":"貴人扶助，諸事大吉","丁口":"親有扶持，眷屬安吉","生意":"同心協力，土可變金","疾病":"醫藥有緣，指日可癒","出行":"有志四方，必有際遇","失物":"偶爾疏忽，完壁歸來","田畜":"孳生長養，善價而沽"},"modern":"籤詩以千里馬自喻：天生好骨架、資質不凡，在大道上奔馳毫無阻礙，只要遇上伯樂，價值立刻被看見。這支籤說你本身條件很好，欠的只是賞識你的人；核心提醒是持續展現實力、多結善緣，貴人一出現，就是一飛沖天的時候。","categories":{"愛情婚姻":"有望遇到真正懂你的知心人，所求可成；真誠相待，這段緣分值得認真經營。","事業工作":"你的能力早晚會被看見，眼前只待伯樂；主動爭取表現機會、經營人脈，遇貴人便能大展身手。","財運":"與人同心協力、合夥經營，平土也能變黃金；單打獨鬥不如找對夥伴。","健康":"與良醫有緣，對症下藥後可望很快痊癒；別諱疾忌醫，及早就診就是轉機。","考試學業":"資質本佳，富貴前定；認真準備並讓師長看見你的努力，考運與機遇都會站在你這邊。","訴訟糾紛":"有貴人相助，諸事大吉；請對人幫忙、找對管道，糾紛可望圓滿化解。","失物行人":"在外的人已在路上，重逢不遠。失物只是一時疏忽，可望完璧歸來，別太焦慮。"}},
  {"id":29,"name":"","level":"上中","poem":["無論築室與開山","方向通時總一般","若遇貴人來拱照","吉凶趨避在其間"],"traditional":"","official":{"功名":"安心待時，必有遇合","行人":"音信遲滯，久而復通","婚姻":"吉星高照，定可成家","官司":"恩星拱照，諸事無妨","丁口":"音信頻通，合門安吉","生意":"貨物揀擇，穩當得利","疾病":"病去如絲，須當擇醫","出行":"客路有緣，出門大吉","失物":"謹慎防閑，不致失財","田畜":"六畜興旺，田園得利"},"modern":"籤詩說無論是蓋房子還是開山闢路，只要方向選對了，做法其實大同小異；再遇上貴人指點扶持，趨吉避凶就都在掌握之中。這支籤的核心是「方向」與「貴人」：大事之前先確認方位與時機，並虛心聽取有經驗者的建議，吉事自然臨門。","categories":{"愛情婚姻":"吉星高照，姻緣可成、可望成家；若有長輩或朋友牽線引薦，更要好好把握。","事業工作":"安心等待時機，該來的際遇不會少；遇到願意提拔你的前輩貴人時，虛心受教就能更上層樓。","財運":"做生意要懂得挑選貨品與標的，精挑細選、穩紮穩打，獲利穩當；田產畜養皆有利。","健康":"病情會慢慢好轉，但關鍵在找對醫生；多方諮詢、慎選醫療方式，康復可期。","考試學業":"先確定志向與方向再全力衝刺；多請教師長過來人，選對目標，努力就不會白費。","訴訟糾紛":"有如恩星拱照，諸事無妨；依循正當程序處理，不會有大問題。","失物行人":"遠方的人音信一度遲滯，但久了自會恢復聯繫。財物只要平時謹慎防範，就不致有損失。"}},
  {"id":30,"name":"","level":"中下","poem":["大海茫茫未有涯","扁舟飄蕩寔堪嗟","我今指引平安路","路在心頭汝自思"],"traditional":"","official":{"功名":"功名遲滯，自悔蹉跎","行人":"魚書雁帛，雲水茫茫","婚姻":"且莫強求，終當有遇","官司":"何須成訟，自反為佳","丁口":"家口未利，保泰求安","生意":"利息平常，安穩為佳","疾病":"凶多吉少，祈禱無妨","出行":"客路艱難，家居為貴","失物":"失物已去，消息全無","田畜":"生息稀少，且有小損"},"modern":"籤詩描繪一葉小船在無邊大海上漂蕩，令人嘆息；但神明點出：平安的路其實不在外面，而在你自己心頭，需要你靜下來想清楚。這支籤的核心是「向內求」：與其向外亂闖亂求，不如先安定心神、認清自己真正要什麼，方向定了，漂泊自然結束。","categories":{"愛情婚姻":"感情先別強求，緣分未到硬追只是空轉；把自己安頓好，該遇到的人終究會遇到。","事業工作":"功名進展遲滯，回頭看或有蹉跎之憾；此刻別再盲目換方向，靜心想清楚定位，再重新出發。","財運":"獲利平平，不宜冒險擴張；以安穩為上，守住本業和本金，等心中有明確方向再行動。","健康":"病況需要特別謹慎看待，務必及早就醫、積極治療，同時安定心情、誠心祈福，多管齊下最穩妥。","考試學業":"成績起伏反映的是方向感不足；先想清楚為何而讀、目標在哪，讀書效率自然回來。","訴訟糾紛":"何必走到興訟？先自我反省、退一步海闊天空；能不告就不告，對你最有利。","失物行人":"遠方的人音信茫茫，一時難有消息，需耐心等候；失物尋回的機會不大，就放下吧，往後多留心。"}},
  {"id":31,"name":"","level":"下下","poem":["神明感格在虔誠","爾未誠心禱豈靈","速向隱微求改悔","免教旦夕禍災生"],"traditional":"","official":{"功名":"富貴在天，妄想何益","行人":"天空海闊，音信渺茫","婚姻":"事多荊棘，追求無益","官司":"自已不仁，於人何尤","丁口":"家中不和，致有災禍","生意":"急流勇退，免得後悔","疾病":"虔誠祈禱，或保無妨","出行":"恐有後悔，及早歸家","失物":"命該失脫，何須煩惱","田畜":"氣象衰微，羽毛憔悴"},"modern":"籤詩直言：神明有沒有感應，全看你誠不誠心；心不誠，再多祈禱也不靈。它勸你趕快回頭檢視那些別人看不到的起心動念，及早改過，才能免去眼前的災禍。這是一支要人反省的籤，但也給了明路——真心悔改、修正言行，轉機就從此刻開始。","categories":{"愛情婚姻":"這段感情阻礙重重，若強求下去只會兩敗俱傷；先誠實面對自己在關係中的問題，該放手時放手。","事業工作":"投機取巧的路走不通，妄想一步登天只是空耗；踏實把眼前的事做好、修正做人做事的態度，才有出路。","財運":"生意投資此刻宜急流勇退，見壞就收，免得日後後悔；別再想以小搏大。","健康":"調養之外，心念也要調整；誠心保養、按部就班治療，並保持善念安穩，可望無大礙。","考試學業":"與其求神保佑，不如先檢討讀書態度是否踏實；改掉僥倖心理、認真補強，成績才會回來。","訴訟糾紛":"這場糾紛恐怕自己也有責任，先反躬自省、主動釋出善意；一味怪罪對方無濟於事。","失物行人":"遠方的人音信渺茫，短期難有消息，先照顧好自己。失物已難尋回，別再懊惱，就當提醒自己往後謹慎。"}},
  {"id":32,"name":"","level":"下下","poem":["雨雪霏霏路不通","人家煙火杳無蹤","算來命運當如此","禱告神明計亦窮"],"traditional":"","official":{"功名":"窮愁潦倒，一事無成","行人":"海角天涯，難覓消息","婚姻":"空費精神，顛倒錯亂","官司":"相爭相競，吉少凶多","丁口":"伶仃困苦，門戶無聊","生意":"本少利微，恐有失誤","疾病":"命犯龍蛇，醫藥罕效","出行":"風浪危險，辛苦徒然","失物":"小有破財，庶免災悔","田畜":"命運不濟，災悔及物"},"modern":"籤詩描繪大雪紛飛、道路不通、四野無人煙的景象——眼前確實是時運最低的谷底，連祈禱都似乎使不上力。但雪總有停的一天：這支籤的核心提醒是，此刻千萬別硬闖，一動不如一靜；收起冒險的念頭，守住基本盤、照顧好自己，安靜等這場風雪過去。","categories":{"愛情婚姻":"此刻談感情容易錯亂空轉、白費心神；先暫停追求，把生活過穩，等運勢回暖再說。","事業工作":"求職謀事處處碰壁，不是努力不夠而是時機太差；先保住現有位置，減少變動，蓄力待時。","財運":"本小利微又容易出錯，任何投資擴張都先踩剎車；就算小有破財，也當作花錢消災，守住大局。","健康":"病況不可輕忽，一般方法見效慢，務必尋求正規醫療、必要時多找幾位醫生評估，並好好休養。","考試學業":"這段時間考運低迷，結果可能不如預期；別因此否定自己，調整策略、留得青山，下一輪再戰。","訴訟糾紛":"爭訟凶多吉少，硬碰硬只會兩敗俱傷；能和解就和解，及早抽身是最好的止損。","失物行人":"遠方的人如在天涯海角，消息難尋，只能耐心等待。失物尋回機會渺茫，就當破小財免大災。"}},
  {"id":33,"name":"","level":"中","poem":["寶物原當密密藏","被人暗損費周章","果然失脫增煩腦","若待尋時在近方"],"traditional":"","official":{"功名":"聰明自露，犯人所忌","行人":"相遇非遥，恐有失誤","婚姻":"機關不慎，難望有成","官司":"漏洩機關，曲多直少","丁口":"家中有災，可無大礙","生意":"同人暗算，利息微薄","疾病":"尋醫不遠，保養小心","出行":"事多阻障，不必遠行","失物":"自不小心，運當失脫","田畜":"不用多思，經營少利"},"modern":"籤詩說寶物本該好好收藏，卻因疏忽被人暗中損害，真的遺失了才煩惱不已；所幸要找的東西就在近處。這支籤的核心是「藏」：才華、財物、計畫都別過度張揚，鋒芒太露容易招忌、機密外洩容易吃虧；謹言慎行、收斂低調，就能避開大半麻煩。","categories":{"愛情婚姻":"感情事宜低調，太早張揚或行事不慎，容易節外生枝難有結果；穩紮穩打、保護好兩人的空間。","事業工作":"你的聰明才幹容易招人忌妒，計畫未成熟前別到處說；防人之心不可無，做好保密再出手。","財運":"獲利本就微薄，還要提防合作對象或同行暗中算計；帳目契約都要清楚,財不露白。","健康":"好醫生不必遠求，就在近處；小心保養、按時調理，健康無大礙。","考試學業":"實力不錯但別鋒芒太露，考前少炫耀、多沉潛；專注自己的步調，避免無謂的比較和干擾。","訴訟糾紛":"己方的把柄或口風若守不住，官司會居於下風；謹言慎行、管好資訊，能和則和。","失物行人":"失物多因自己疏忽，但別灰心——東西就在近處，仔細找找常去的地方。在外的人重逢不遠，只是過程恐有小波折。"}},
  {"id":34,"name":"","level":"上","poem":["君來未卜我先知","欲向前途問險夷","好待桃花春浪發","龍門一躍是良期"],"traditional":"","official":{"功名":"官運已通，功名得志","行人":"春風送暖，好音便來","婚姻":"婚姻可成，且待佳麗","官司":"吉人天相，事事稱心","丁口":"春色盈門，長幼咸吉","生意":"處處生財，交春更好","疾病":"宿疾漸瘳，逢春漸癒","出行":"此去得意，衣錦榮歸","失物":"小心防範，百無一失","田畜":"雞黍多利，桑麻倍利"},"modern":"籤詩說「你還沒開口，神明已先知道你的來意」——你想問前途吉凶，答案是：等到桃花盛開、春水上漲之時，正是鯉躍龍門的大好時機。這是一支上籤，核心提醒是：好運已定，關鍵在把自己準備好；春天一到、時機一來，全力一躍便能功成名就。","categories":{"愛情婚姻":"婚姻可成，而且會遇到很好的對象；不必急，等到春暖時節，良緣自然水到渠成。","事業工作":"官運事業運已經打通，升遷高就大有可為；把握春天前後的機會全力表現，一躍而上。","財運":"處處生財，財源廣進，開春之後更旺；正財偏財皆有利,可以放心佈局。","健康":"老毛病正在逐漸痊癒，入春後會明顯好轉；安心調養，康復可期。","考試學業":"這是「魚躍龍門」的考試好籤，金榜有望；穩住步調衝刺到底，春季的大考正是你的良期。","訴訟糾紛":"吉人自有天相，事事稱心；糾紛可望順利化解，不必掛心。","失物行人":"遠方的人如春風送暖，好消息很快到來。失物只要小心防範查找，可望萬無一失。"}},
  {"id":35,"name":"","level":"上中","poem":["乘雲馭氣一神仙","來到南方結善緣","欲買金舟求不死","須將牛犬戒為先"],"traditional":"","official":{"功名":"戒食牛犬，自得功名","行人":"薰風南來，遇我知已","婚姻":"丙丁作合，丑戌當忌","官司":"貴人有緣，提拔得力","丁口":"家室平安，當結善緣","生意":"財出南方，必得大利","疾病":"誠心齋戒，祈禱必安","出行":"遵海而南，利有攸往","失物":"小有失脫，須當戒慎","田畜":"入夏以來，頗有生色"},"modern":"籤詩描繪仙人乘雲駕氣來到南方結善緣，但點出想求得真正的福分，得先從戒除口腹之欲、持守善行做起。這支籤的方位在南方、關鍵在「戒」與「善」：機運已在路上，能不能接住，取決於你願不願意先約束自己、廣結善緣。","categories":{"愛情婚姻":"姻緣有望撮合，夏季（丙丁）前後時機尤佳；但要避開不合適的時點勉強行事，順著吉期走最穩。","事業工作":"有貴人願意提拔，往南方發展特別有利；先把品行操守顧好，機會來時自然被託付重任。","財運":"財位在南方，往南發展、與南方往來的生意可得大利；同時多做善事，財氣更旺。","健康":"誠心齋戒、清淡飲食，配合祈福調養，身體可保平安；這支籤特別提醒管住嘴、養好生活習慣。","考試學業":"考運不差，但要先收心：戒除玩樂欲望、生活自律，功名自然到手。","訴訟糾紛":"與貴人有緣，會有人出面幫你斡旋；態度良善配合，糾紛可獲妥善處理。","失物行人":"在外的人乘著南風而來，可望遇見或收到消息。財物或有小失，往後要更加謹慎收存。"}},
  {"id":36,"name":"","level":"上中","poem":["逢蛇遇虎多驚恐","須識山行遜水行","借汝一帆風力順","陶朱貨殖有榮名"],"traditional":"","official":{"功名":"捨北圖南，榮光指日","行人":"順風揚帆，目前可到","婚姻":"如係東南，更增光輝","官司":"貴人抬眼，自有照應","丁口":"家室富有，人口康寧","生意":"去陸就水，利息十分","疾病":"指日痊可，不必驚疑","出行":"出門順利，際會風雲","失物":"失物未遠，當在水濱","田畜":"種竹養魚，獲利加倍"},"modern":"籤詩說走山路會遇蛇虎、驚險重重，不如改走水路；借你一帆順風，便能像陶朱公（范蠡）一樣經商致富、名利雙收。這支籤的核心是「選對路徑」：同樣的目標，換一條路走就從逆境變順境；捨北就南、去陸就水，順風的方向已經為你備好。","categories":{"愛情婚姻":"姻緣可成，若對象來自東南方向更是錦上添花；順著自然的節奏發展，這段感情前景光明。","事業工作":"在原地或北方發展多阻礙，轉往南方或換個領域，榮景指日可待；貴人也會適時出手相助。","財運":"這是經商大利的籤——「去陸就水」，與水運、貿易、流通相關的財路獲利豐厚；養魚種竹之類的投資也加倍得利。","健康":"不必驚慌疑神疑鬼，病痛指日可癒；安心治療休養即可。","考試學業":"換個方向努力就海闊天空：調整志願、科系或讀書方法，避開硬碰硬的路線，成果反而亮眼。","訴訟糾紛":"有貴人青睞照應，糾紛自有人幫忙圓場；不必硬拚，借力使力即可化解。","失物行人":"失物離你不遠，往有水的地方找找（水邊、浴室、水槽附近）。在外的人一帆風順，眼前就會到來。"}},
  {"id":37,"name":"","level":"中中","poem":["骨肉緣何有異心","自因疾病苦相侵","勸汝改圖行孝弟","挽回造化莫因循"],"traditional":"","official":{"功名":"欲求榮顯，先篤天倫","行人":"雲樹迷離，望之不見","婚姻":"事情未順，只恐難成","官司":"理屈詞窮，挽回宜急","丁口":"家門不和，致多戾氣","生意":"家門和好，黃土變金","疾病":"自作之孽，祈禱須誠","出行":"學做善人，然後可行","失物":"自不小心，命當破耗","田畜":"田園荒落，六畜蕭條"},"modern":"籤詩問：骨肉至親為何離心離德？正因家中不和，才招來疾病煩憂纏身。它勸你回頭修好孝悌之道、善待家人，命運就能挽回，切莫拖延因循。這支籤的核心在「家和」：眼前諸事不順的根源在家庭關係，先把家人的心結解開，運勢自然跟著轉。","categories":{"愛情婚姻":"感情目前不順，恐怕與雙方家庭或彼此心結有關；先修復關係、真誠溝通，勉強推進難有好結果。","事業工作":"想求發展，先把家裡安頓好；後院起火事業難成，家庭和睦了，工作自然有餘裕衝刺。","財運":"「家和萬事興」正是這支籤的財訣——家門和好，黃土也能變金；家人同心，財路才會開。","健康":"病痛與長期的心結、鬱氣有關；除了就醫調養，更要誠心化解與家人的嫌隙，心結解了病才好得快。","考試學業":"想有好成績，先讓家裡氣氛安定；與家人和好、心無罣礙，讀書才靜得下來。","訴訟糾紛":"這場糾紛你方理據偏弱，拖越久越不利；趕快主動和解、亡羊補牢，及早收場為上。","失物行人":"遠方的人一時音訊不明、望不見蹤影，需耐心等待。失物多因自己疏忽，恐難尋回，就當破財消災。"}},
  {"id":38,"name":"","level":"上中","poem":["莫道神明事渺茫","誠心禱告降嘉祥","福緣善慶真無爽","天道昭昭曲直彰"],"traditional":"","official":{"功名":"欲望功名，須先積德","行人":"旬日之後，當有好音","婚姻":"事當誠求，姻緣有望","官司":"神靈默佑，庶可平安","丁口":"若要家安，須行善事","生意":"輕財樂施，必獲大利","疾病":"祈安保泰，勿藥有喜","出行":"修德行仁，何往不利","失物":"自已疏忽，無悔亡羊","田畜":"念念作德，物物生財"},"modern":"籤詩說別以為神明之事虛無縹緲——誠心禱告自有吉祥降臨；行善積德必有福報，天道明明白白，是非曲直終會彰顯。這支籤的核心是「積善」：你求的事情有望，但福分要用善行去換；平日多行好事、待人厚道，好運會實實在在回到你身上。","categories":{"愛情婚姻":"以誠相待、真心追求，姻緣大有希望；感情裡不玩心機，越真誠越有福。","事業工作":"想求功名成就，先從積德做起；口碑和人品累積起來，機會與貴人自然找上門。","財運":"這支籤的財法很特別——「輕財樂施，必獲大利」；肯分享、肯回饋，反而財源滾滾。","健康":"安心祈福、保持善念平和，病痛不藥而癒；心安則身安。","考試學業":"踏實用功加上平日善行，考運自然眷顧；懷著感恩的心應試，發揮會超乎預期。","訴訟糾紛":"行得正坐得端，自有神靈默佑；只要問心無愧，糾紛可望平安落幕。","失物行人":"遠方的人約十天之後會有好消息，安心等候。失物是自己一時疏忽，找不回也別懊悔，記取教訓即可。"}},
  {"id":39,"name":"","level":"中","poem":["我本慈航大士身","扶危救苦濟紅塵","吉凶禍福雖前定","善念一萌神鬼欽"],"traditional":"","official":{"功名":"大善回天，富貴必得","行人":"音信已通，目前可到","婚姻":"姻緣前定，守正則吉","官司":"急性者凶，敬慎者吉","丁口":"積善之家，必有餘慶","生意":"無愧神明，勤必有利","疾病":"神靈庇佑，勿藥有喜","出行":"步步行仁，避凶趨吉","失物":"小心提防，可無差失","田畜":"生財有道，先看存心"},"modern":"這支籤以觀音大士（慈航）的口吻說：我本是扶危救苦、普濟世人的菩薩；吉凶禍福雖說命中注定，但只要你萌生一個善念，連神鬼都會敬重你。核心提醒是：命運不是死的——存好心、行好事，就是最有力的改運法；遇事守正不躁，福報自然跟上。","categories":{"愛情婚姻":"姻緣是前世註定的緣分，守住正道、真誠以待就吉利；不越軌、不強求，感情自然安穩。","事業工作":"行善積德到一定程度，富貴自然來；工作上憑良心做事、與人為善，成就會水到渠成。","財運":"賺錢只要無愧於心、勤勞打拚，必有利潤；君子愛財取之有道，正財最旺。","健康":"有神靈庇佑，病痛可望不藥而癒；保持心地善良平和，就是最好的養生。","考試學業":"心存善念、踏實用功，考運自有加持；別想旁門左道，正正當當準備就是上策。","訴訟糾紛":"這支籤講得很清楚：急躁強硬者凶，恭敬謹慎者吉；放軟身段、按規矩來，結果對你有利。","失物行人":"遠方的人音信已通，眼前就會到來。財物只要平時小心提防，就不會有差錯。"}},
  {"id":40,"name":"","level":"下下","poem":["汝今心地不分明","枉向神前禱告頻","富貴榮華無汝分","官非口舌與逡巡"],"traditional":"","official":{"功名":"妄作誤為，常不飽煖","行人":"霧障雲封，歸心未決","婚姻":"本非可圖，求之無益","官司":"官法如爐，難逃秉鑒","丁口":"乖氣致戾，當有災悔","生意":"妄想得利，反致破財","疾病":"自取之禍，祈禱無益","出行":"落落萍踪，惟悲失路","失物":"逆來順受，報應無差","田畜":"田園將蕪，木凋草枯"},"modern":"籤詩直言：你如今心念不清不正，就算頻頻到神前祈禱也是枉然；照這樣下去，富貴榮華與你無緣，還可能惹上官司口舌，進退兩難。這是一支警醒的下下籤，但路並沒有堵死——先把心念與行事擺正、遠離是非爭端、不投機不妄求，運勢自然能從谷底慢慢轉回。","categories":{"愛情婚姻":"這段感情本來就不該強求，越追越沒有結果；誠實面對它不適合的事實，放手才是對彼此的善待。","事業工作":"投機妄為只會越走越窄，難有安穩；回到正軌踏實做事、不抄捷徑，才是重建運勢的起點。","財運":"妄想快錢反而破財，任何高報酬的誘惑此刻都要拒絕；守住本業、量入為出，先止血再談獲利。","健康":"病痛多與自己的生活方式和心態有關，光祈禱沒有用；下決心改掉壞習慣、配合正規治療，才是真正的解方。","考試學業":"心浮氣躁、投機取巧，成績自然不會好；收心歸零、老老實實下功夫，是唯一的路。","訴訟糾紛":"這支籤特別警示官非口舌——法網恢恢，僥倖心態最危險；務必誠實面對、依法處理，切莫再火上加油。","失物行人":"遠方的人行蹤漂泊、歸期未定，只能耐心等候。失物難以尋回，就坦然接受這個提醒，往後心正行正，自然少破財。"}},
  {"id":41,"name":"","level":"上中","poem":["百工執業各須專","自有財源漸漸添","過得殘冬春又至","東風烘暖換新年"],"traditional":"","official":{"功名":"欲求功名，先須努力","行人":"春信一通，故人可遇","婚姻":"專心誠求，交春有望","官司":"且待開春，自有好音","丁口":"人口粗安，明春更好","生意":"專心致志，日久生財","疾病":"專心醫治，逢春始痊","出行":"順水行舟，春潮相送","失物":"謹守繩尺，可無差失","田畜":"捨舊圖新，倍有生色"},"modern":"這首籤以百工各守其業起筆：只要專心把本分做好，財源自然一點一滴累積；熬過殘冬，春天一到、東風送暖，就是換上新氣象的時候。整體是穩健向上的好籤，核心提醒是「專」與「等」——不必急著求快，把眼前的事做深做精，好轉的時節自然會來。","categories":{"愛情婚姻":"感情要專一誠懇地經營，不宜三心二意；官方批註說「交春有望」，用心對待，開春前後會有好消息。","事業工作":"把心力放在自己的專業上，日久必見成果；與其頻頻換跑道，不如在本業裡扎根，該汰舊換新的地方大膽更新，會更有起色。","財運":"財不是一夜暴富型，而是漸漸添增型；專心致志、按部就班，收入會穩定成長，年關過後更見起色。","健康":"調養要有耐心，找定一位可信的醫師專心治療，不要頻換方法；入春之後身體會明顯好轉。","考試學業":"想求功名就得先下苦功，這支籤給努力的人加分；穩紮穩打地讀，成績會隨著累積慢慢浮現。","訴訟糾紛":"眼下不必急著攤牌，稍安勿躁；等過了年、開春之後自有好消息，急躁反而壞事。","失物行人":"失物只要平日謹慎收存，多半沒有大損失，循著平常放置的規矩找找看；等候的人開春會有音信，故人可望重逢。"}},
  {"id":42,"name":"","level":"上","poem":["十分財喜到君家","從此謀為事事嘉","管取一生康且泰","春風看徧上林花"],"traditional":"","official":{"功名":"福祿天成，功成名就","行人":"燈花報喜，好音頻來","婚姻":"婚姻和合，財喜重重","官司":"吉人天相，凡事平安","丁口":"日日平安，時時吉慶","生意":"財氣穩足，動作如意","疾病":"身躬康泰，消災解厄","出行":"順風揚帆，利有攸往","失物":"財氣不散，去而復來","田畜":"物物豐盛，處處生財"},"modern":"「十分財喜到君家」開門見山：財富與喜事一起上門，之後做什麼都順，一生健康平安，就像春風吹遍上林、繁花盛開。這是一支難得的大吉籤，提醒是好運當前更要惜福守正，別因順遂而鬆懈或揮霍，福氣才留得久。","categories":{"愛情婚姻":"姻緣和合、喜事帶財，單身者有良緣可期，有伴侶者感情穩定甜蜜，是適合論及婚嫁的時機。","事業工作":"所謀之事樣樣順遂，計畫可以放心推進；名利雙收在望，但成事之後仍要謙和待人，好運才走得長。","財運":"財氣充足穩固，投資、生意動作都容易如願；各處都有生財機會，唯獨別因為順手就孤注一擲。","健康":"身體康泰、災厄消解，是健康無虞的好籤；維持現有的好習慣，就能長保安康。","考試學業":"福祿天成、功成名就，考運正旺；把實力備齊，這次的努力很有機會開花結果。","訴訟糾紛":"吉人自有天相，紛爭可望平安化解；以和為貴處理，結果對你有利。","失物行人":"財氣不散，遺失的東西有「去而復來」之象，耐心找回機會很大；等候的人喜訊頻傳，好消息不久就到。"}},
  {"id":43,"name":"","level":"中","poem":["夏秋未免多啾唧","冬至方教境遇昌","莫近細人增口舌","好修陰騭卻災殃"],"traditional":"","official":{"功名":"中年未利，晚景方佳","行人":"雁足傳書，十月可遇","婚姻":"遲則有成，還須謹慎","官司":"存心行已，不必責人","丁口":"夏秋啾唧，冬至平安","生意":"夏秋平平，交冬得利","疾病":"悔過遷善，交冬自癒","出行":"踏雪尋梅，頗有樂境","失物":"破財流年，交冬平善","田畜":"六節未佳，三冬方好"},"modern":"籤詩直說：夏秋兩季難免瑣事煩擾、不太平靜，要到冬至前後處境才會轉好；並叮嚀別靠近搬弄是非的小人，多積陰德才能化解災殃。這是一支講「時機加修為」的中平籤——上半年多忍耐、少捲入口舌，默默行善，冬天自然否極泰來。","categories":{"愛情婚姻":"感情進展宜慢不宜快，年底前後才容易水到渠成；過程中要謹慎，別讓旁人的閒言閒語動搖了彼此。","事業工作":"中段時運平平，容易被雜音干擾，晚一點才見佳境；遠離愛挑撥的人，專心做事，冬季後局面轉順。","財運":"夏秋收成普通，甚至有小破財之象，入冬後財運才轉旺；這段期間保守理財、少聽明牌。","健康":"夏秋容易有些小病痛纏身，入冬可望痊癒；官方也提醒「悔過遷善」，作息歸正、心平氣和，恢復更快。","考試學業":"近期考運未開，屬於後發型；別因一時成績起伏氣餒，持續耕耘，晚一點的關鍵考試更有利。","訴訟糾紛":"這支籤勸你反求諸己、莫與人爭口舌；能不糾纏就不糾纏，把心放在自己站得住的道理上，事情自然淡化。","失物行人":"近期財物有耗損之象，入冬後才平順，重要物品先收妥；等候的人約在農曆十月前後會有書信或消息。"}},
  {"id":44,"name":"","level":"下下","poem":["看來黑白要分明","棋子縱橫布滿枰","汝卻不知先一著","枉勞心力總難贏"],"traditional":"","official":{"功名":"自已蹉跎，功名難就","行人":"水遠山長，知音難遇","婚姻":"幾當先決，緩則無濟","官司":"詞窮理屈，自悔已遲","丁口":"門庭冷落，丁眷多災","生意":"從前失算，圖利空虛","疾病":"自不保身，服藥罔效","出行":"跋涉艱難，徒悲岐路","失物":"命當破財，悔之何益","田畜":"六畜消耗，雞犬不寧"},"modern":"籤詩以下棋為喻：棋子布滿整盤、黑白看似分明，你卻總是慢人一步、少算了先手，再怎麼費心也難以取勝。這是一支下下籤，但它點出的問題很具體——不是命定失敗，而是謀劃不足、起步太慢。與其硬拚，不如先停下來重新盤整：把局勢看清、把該做的準備補上，甚至該收手的就收手，避免越陷越深。","categories":{"愛情婚姻":"感情上若已錯過表態或決定的時機，拖延只會讓局面更僵；該說清楚就趁早說清楚，勉強硬撐的關係不如坦誠面對。","事業工作":"先前的規劃可能有失算之處，現在不宜貿然加碼；暫停腳步、重新檢視策略，把「先一著」補回來，比埋頭苦撐更重要。","財運":"近期財運不濟，圖利多半落空，投資與大額支出都先踩煞車；接受小損、守住本金，就是這段時間最好的理財。","健康":"身體發出的警訊別再拖，光靠吃藥而不調整生活習慣效果有限；及早就醫、好好保養，情況仍可穩住。","考試學業":"過去若有蹉跎，這次難免吃力；與其懊悔，不如重整讀書計畫、把基礎補起來，為下一次機會提早布局。","訴訟糾紛":"官方批註直言「詞窮理屈」，硬爭下去恐怕站不住腳；及早尋求和解、停損收場，遠比纏訟到底划算。","失物行人":"失物尋回的機會不大，就當破財消災，別再耗費心力追討；等候的人山高水遠、音信難通，需有長期等待的心理準備。"}},
  {"id":45,"name":"","level":"上","poem":["官爵巍巍未可量","君恩隆重世無雙","船頭助汝風帆穩","萬里封侯大吉昌"],"traditional":"","official":{"功名":"祿位功名，未可限量","行人":"正遇順風，行踪即到","婚姻":"得勢得時，攸往盡利","官司":"太陽高照，陰氣俱消","丁口":"家門清吉，人口平安","生意":"財運亨通，左宜右有","疾病":"精神強旺，勿藥有喜","出行":"利涉大川，百事如意","失物":"尋踪覓跡，只在眼前","田畜":"暢茂條達，財氣有餘"},"modern":"這首籤氣象宏大：官爵之高不可限量、恩遇之隆世間少有，又有人在船頭助你、風帆平穩，直指「萬里封侯」的大吉大昌。是求功名事業者的絕佳好籤，貴人與時勢都站在你這邊。提醒只有一句：順風時更要把穩方向、心懷感恩，成就才配得上這份際遇。","categories":{"愛情婚姻":"得時得勢、諸事皆利，感情進展順風順水；提親、論嫁、修復關係都是好時機，大方主動即可。","事業工作":"前途不可限量，升遷、轉職、開創新局都有貴人相助；放手去做，格局可以拉大。","財運":"財運亨通、左右逢源，正財偏財皆有餘裕；乘勢布局沒問題，但記得順風時也要留些餘糧。","健康":"精神強旺、不藥而癒之象，健康無須過慮；維持規律作息，元氣自然充沛。","考試學業":"祿位功名未可限量，是考試升學的上上籤；全力以赴，名次很可能超乎預期。","訴訟糾紛":"如太陽高照、陰霾盡消，是非可望還你清白；正面應對，結果明朗有利。","失物行人":"失物就在眼前不遠處，循著足跡仔細找，很快能尋獲；等候的人正遇順風，行蹤即到。"}},
  {"id":46,"name":"","level":"下下","poem":["孤蹤飄泊等浮萍","欲渡無舟枉問津","若使當年行善事","何須今日叩神明"],"traditional":"","official":{"功名":"自不潛修，功名無分","行人":"行踪漂泊，音信虛無","婚姻":"途窮孤另，何以為家","官司":"爾不自諒，於人何尤","丁口":"丁眷有災，當行善事","生意":"財氣空虛，不必妄想","疾病":"誠心祈禱，改過自新","出行":"蹈危履險，跼蹐難安","失物":"自不小心，須當破耗","田畜":"命運不齊，諸事破耗"},"modern":"籤詩描寫孤身漂泊如浮萍、想渡河卻無船可搭的窘境，並直白點破：若平日多行善事，何至於今日才來求神？這是一支下下籤，但它的重點不在斷你絕路，而在指出出路——從現在開始改過行善、踏實積德，處境就會慢慢有依靠。求外援之前，先把自己站穩。","categories":{"愛情婚姻":"目前姻緣路上較為孤單，勉強湊合難以成家；先把生活與心安頓好、與人為善，緣分才有落腳的地方。","事業工作":"時運未濟、缺乏奧援，大動作暫緩；與其怨環境，不如充實自己、修補人脈，用可靠的口碑重新累積機會。","財運":"財氣空虛，投機妄想只會更失血；守住基本開銷、不借貸冒險，先止血再談翻身。","健康":"調養之外，官方批註強調「誠心祈禱、改過自新」——把傷身的習慣戒掉、心念放正，身體才有好轉的根基。","考試學業":"平時不下功夫，臨場自然無分；這次結果不理想別灰心，從今天起老實累積，下一回才有底氣。","訴訟糾紛":"批註直言「爾不自諒，於人何尤」——先檢討自身站不站得住腳；能和解就和解，別把力氣耗在怪罪對方。","失物行人":"失物多因自己疏忽，尋回不易，就當一次教訓，日後謹慎收存；等候的人行蹤漂泊、音信渺茫，暫時不必苦等，先過好自己的日子。"}},
  {"id":47,"name":"","level":"中","poem":["同舟共命諺誠然","究竟中分善惡緣","卻看一輪明月上","清光照徹見媸妍"],"traditional":"","official":{"功名":"善惡果報，得失自知","行人":"清光照人，中旬可遇","婚姻":"妍媸勿論，喜得團圓","官司":"自問曲直，乃見輸贏","丁口":"家口平安，須當作福","生意":"刁惡愈窮，善人是富","疾病":"悔過從善，祈禱為安","出行":"此去平平，為善則佳","失物":"旬月之中，須防失脫","田畜":"利息平常，無甚生息"},"modern":"籤詩說同舟共命固然不假，但船上的人終究要分出善緣惡緣；待明月升起、清光照徹，美醜善惡便無所遁形。這是一支講「因果分明」的中平籤：事情的成敗得失，取決於你憑不憑良心做事。守住善念與誠信，真相與公道自然站在你這邊。","categories":{"愛情婚姻":"別太計較外在條件，重點是彼此心地與相處的誠意；能坦誠相待，就有團圓和合之喜。","事業工作":"與人合夥共事要慎選夥伴，日久見人心；自己行得正，成果自然歸於你，取巧的路走不遠。","財運":"官方批註說得直白：「刁惡愈窮，善人是富」——正當經營才留得住財，投機刻薄反而漏財。","健康":"身心是一體的，心安則體安；有小恙不妨誠心調養、放下計較，恢復會更順利。","考試學業":"一分耕耘一分收穫，這支籤的得失全看平日累積；踏實準備的人不會被虧待。","訴訟糾紛":"先自問曲直——理在你這邊，就沉著應對，公道如明月照徹終會顯明；理虧之處則趁早修正或和解。","失物行人":"近期（尤其月中前後）要留意財物，防範遺失勝於事後追討；等候的人約在中旬可望相見，如清光照人。"}},
  {"id":48,"name":"","level":"中下","poem":["千方百計總皆空","枉費心機不見功","直待雪消紅日上","另開局面漸亨通"],"traditional":"","official":{"功名":"時運未通，且宜坐守","行人":"音信遲延，開春即到","婚姻":"此處未諧，另求為吉","官司":"官非口舌，吉少凶多","丁口":"今歲欠寧，交春方穩","生意":"先貧後富，運到得利","疾病":"病勢遷延，開春自癒","出行":"今歲未到，臘盡方佳","失物":"運值破財，必有失脫","田畜":"目下未利，且待春和"},"modern":"籤詩坦白：眼下千方百計都落空、費盡心機不見成效，要等到冰雪消融、紅日升起，另開新局才會漸漸亨通。這是中下籤，但方向很清楚——問題不在你不夠努力，而在時機未到、路子不對。先停止在原地硬耗，養精蓄銳，等開春時節換個方式重新出發。","categories":{"愛情婚姻":"官方批註明示「此處未諧，另求為吉」——眼前這段緣分若處處卡關，不必勉強強求；放下執著，更合適的緣分在後頭。","事業工作":"現行的做法已證明行不通，再加碼只是空耗；沉住氣坐守一陣，等時機轉暖時「另開局面」，轉型或換跑道反而漸入佳境。","財運":"先貧後富之象：目前求財多阻，別急著翻本；守到運勢回轉，該你的利潤自然到手。","健康":"病情可能拖延一段時間，別因見效慢就亂投醫；耐心調養，開春之後可望自然痊癒。","考試學業":"這一輪時運未通，結果可能不如預期；把它當作蹲低蓄力，調整讀書方法，來年春天後的機會才是你的主場。","訴訟糾紛":"官非口舌吉少凶多，是這支籤最需要小心的一項；能避就避、能和解就和解，千萬別逞一時之氣把事情鬧大。","失物行人":"近期正值破財之運，失物恐難尋回，重要物品務必收妥防範；等候的人音信遲延，要到開春才會到來。"}},
  {"id":49,"name":"","level":"上","poem":["貴人相見便相親","真覺風光遠過人","無限榮華從此始","青春努力莫辭勤"],"traditional":"","official":{"功名":"富貴功名，未可限量","行人":"故人千里，相聚目前","婚姻":"良緣會合，家運興隆","官司":"貴人有緣，風光自勝","丁口":"家室清寧，無災無悔","生意":"利有攸往，財運亨通","疾病":"吉星拱照，災厄自消","出行":"處處有緣，出門大利","失物":"謹慎防範，自無差失","田畜":"田園豐盛，物產滋榮"},"modern":"籤詩描寫遇見貴人一見如故、風光遠勝旁人，無限榮華從此開始——但末句話鋒一轉：「青春努力莫辭勤」。這是一支貴人運極旺的上籤，機會與人脈都會來敲門；核心提醒是好運要配上勤奮才接得住，趁著正當年，別偷懶。","categories":{"愛情婚姻":"良緣會合、一拍即合之象，遇到投緣的人不妨主動經營；成家之後家運興隆。","事業工作":"貴人提攜加上自身努力，是事業起飛的組合；多出席場合、多結善緣，升遷與新機會就在人與人的相遇裡。","財運":"財運亨通、利有攸往，投資與開展業務都順；趁勢勤快耕耘，收穫會一波接一波。","健康":"吉星拱照、災厄自消，健康大致無虞；年輕本錢再好也別揮霍，規律生活讓好狀態延續。","考試學業":"富貴功名未可限量，考運與努力相乘；此時多讀一分就多得一分，切莫因自恃聰明而懈怠。","訴訟糾紛":"有貴人緣相助，紛爭可望體面收場；請可信的長輩或專業人士出面協調，事半功倍。","失物行人":"平日多加謹慎防範，自然不會有損失，遺失了也往常走動之處找找；等候的人雖在千里之外，相聚就在眼前。"}},
  {"id":50,"name":"","level":"上","poem":["神仙事業由前定","行向東來更向南","取坎填離成大業","長生不死是奇男"],"traditional":"","official":{"功名":"勤學功成，德盛名至","行人":"春風披拂，遇在東南","婚姻":"水火既濟，求無不利","官司":"喜遇貴人，扶持得力","丁口":"家門清吉，長幼咸安","生意":"財氣充足，頗多生色","疾病":"調養元氣，自能長生","出行":"驅車出門，利在東南","失物":"東南尋之，失而復得","田畜":"物產孳生，田園成熟"},"modern":"籤詩帶著道家煉養的意象：大業如神仙事業般早有安排，行向東、再向南，以坎填離、水火既濟，終能成就非凡。這是一支上籤，暗示只要方向對了（東南方尤其有利）、陰陽調和不偏廢，事情就會順理成章。提醒是成大事靠的是持續修煉與布局，不是一步登天。","categories":{"愛情婚姻":"水火既濟、剛柔互補，兩人個性互相成全，是能長久的好緣分；有求皆利，可放心走下去。","事業工作":"勤學修煉終能功成名至，發展方位以東南為佳；把不同資源整合互補，正是你成大業的關鍵手法。","財運":"財氣充足、頗有起色，往東南方向的機會或市場尤其值得經營；穩健布局，收成可觀。","健康":"重點在調養元氣：睡眠、飲食、運動平衡了，自然精神長旺；別靠透支硬撐。","考試學業":"勤學功成、德盛名至——這支籤最疼用功的人；按部就班修煉實力，成果水到渠成。","訴訟糾紛":"喜遇貴人、扶持得力，有能人相助則糾紛可解；主動尋求專業協助，不必單打獨鬥。","失物行人":"失物往東南方向尋找，有失而復得之象；等候的人如春風披拂，相遇也應在東南方。"}},
  {"id":51,"name":"","level":"中","poem":["天河清淺不生波","歲歲雙星安穩過","今屆秋期風浪發","恐驚織女起婆娑"],"traditional":"","official":{"功名":"安穩成名，恐有後變","行人":"若屆秋期，防有驚險","婚姻":"好椿喜事，恐有反覆","官司":"莫道平安，還須把穩","丁口":"童叟平安，陰人有咎","生意":"春夏生財，秋間不利","疾病":"小有驚恐，大限無妨","出行":"出門安穩，秋來小心","失物":"月逢七八，恐防失脫","田畜":"四季平和，秋成小利"},"modern":"籤詩借牛郎織女為喻：天河清淺、年年安穩相會，偏偏今年秋天起了風浪，恐怕連織女都要受驚。整體是「平順中藏變數」的中平籤——上半年大致安穩，但入秋（約農曆七、八月）前後要特別留心反覆與驚擾。核心提醒：別因一路平順就掉以輕心，關鍵時節把穩了，就能安然度過。","categories":{"愛情婚姻":"好事在望，卻恐有反覆變卦之象；越接近成局越要細心溝通，別在秋天讓誤會起風浪。","事業工作":"前期成事順利，但成了之後仍可能生變；重要案子在秋季前後要多留一手，確認再確認。","財運":"春夏生財順遂，秋季轉為不利；上半年賺到的要守住，入秋後避免新的大額投入。","健康":"或有小驚小恐，但無大礙；家中長輩小孩平安，女性成員要多留意身體，別硬撐。","考試學業":"平時實力足以安穩過關，怕的是臨場或放榜後的變數；細節分數別大意，志願選填等後續程序也要謹慎。","訴訟糾紛":"官方提醒「莫道平安，還須把穩」——看似和解在望也別鬆懈，文件與承諾都落實白紙黑字，以防翻案。","失物行人":"農曆七、八月前後最容易遺失財物，貴重物品提前收好；等候的人若在秋天趕路，提醒對方注意安全，行程或有驚險但可化解。"}},
  {"id":52,"name":"","level":"中","poem":["寶鏡塵埋久未磨","一朝拂拭起光華","本來神物稱奇秘","魑魅潛形洵足誇"],"traditional":"","official":{"功名":"篤志潛修，久而必發","行人":"契闊經年，相逢八月","婚姻":"從此團圓，永無駁雜","官司":"貴人抬眼，便有風光","丁口":"人口清吉，災禍不生","生意":"貨物認真，終獲大利","疾病":"元氣既復，陰邪盡消","出行":"明珠暗投，逢時則出","失物":"小心防患，陰人自退","田畜":"靜以待時，終久得利"},"modern":"籤詩以寶鏡為喻：明鏡蒙塵已久，一旦拂拭便光華四射，本是神物、自能照退魑魅魍魎。這是一支「懷才待時」的籤——你的實力或價值暫時被埋沒，但只要持續打磨、不自暴自棄，時機一到自然大放異彩，小人邪祟也近不了身。提醒是沉潛期別急著證明自己，把功夫練足最要緊。","categories":{"愛情婚姻":"撥雲見日、從此團圓之象，久經波折的感情可望修成正果，之後不再有雜音；珍惜這份得來不易的安定。","事業工作":"篤志潛修、久而必發：目前的低調不是埋沒，是累積；等貴人抬眼的那一刻，你的價值會被看見。","財運":"貨真價實是你的財路——認真對待品質與信用，終獲大利；靜以待時，別為快錢降低格調。","健康":"元氣恢復之後，陳年的小毛病會跟著消退；調養以固本為主，把底子養回來。","考試學業":"像磨鏡一樣磨實力：平日下的苦功此刻或許看不出來，時候到了必然發光；耐住性子繼續累積。","訴訟糾紛":"有貴人青睞相助，是非可望澄清、還你清白；沉著應對，讓事實替你說話。","失物行人":"小心防範便可保財物無虞，暗中覬覦的人自會退去；等候的人分別經年，約在農曆八月可望重逢。"}},
  {"id":53,"name":"","level":"中中","poem":["急水灘頭快著篙","艄公把舵更應牢","須教出得風波險","方見舟師手段高"],"traditional":"","official":{"功名":"吃盡辛苦，方得顯榮","行人":"行人遲滯，方有好音","婚姻":"勞心成就，還要提防","官司":"事多驚疑，挽回須急","丁口":"存心行善，可保安寧","生意":"利覓蠅頭，勞心費力","疾病":"病勢危險，終久得安","出行":"道路艱難，出險就夷","失物":"防存嚴緊，可以無失","田畜":"勞心勞力，不致損傷"},"modern":"籤詩畫面緊張：急流灘頭要快撐篙、舵手更得把穩，能衝出這段風波險灘，才顯得出真本事。這是一支「考驗當前」的中平籤——眼下確實辛苦驚險，但撐得過去就是你的能耐證明。核心提醒：關鍵時刻動作要快、心要穩，該補救的立刻補救，別猶豫拖延。","categories":{"愛情婚姻":"這段感情要費心經營才能成，成了之後也還得用心維護；別以為過了一關就一勞永逸。","事業工作":"吃盡辛苦方得顯榮：現在正是最顛簸的一段，穩住方向、快速應變，衝過去就是一片開闊。","財運":"利潤如蠅頭、賺得勞心費力，這陣子求財辛苦但不至於虧空；控管風險，別在急流中貪大注。","健康":"病勢或有一段危險期，令人擔憂，但終究能轉危為安；積極配合治療、不放棄，是度過難關的關鍵。","考試學業":"這場硬仗要熬得住壓力，過程煎熬但結果值得；越接近考期越要穩住節奏，臨場沉著就是你的高手段。","訴訟糾紛":"事多驚疑、變數不少，要挽回就得趁早出手；立刻整理證據、尋求專業協助，拖延只會讓局面更難收拾。","失物行人":"財物看管嚴謹就不會有損失，這陣子出入多留心隨身物品；等候的人路上耽擱遲滯，晚些才有好消息，不必過度擔憂。"}},
  {"id":54,"name":"","level":"中","poem":["從前作事總糊塗","此後修為要切磋","若得一心行正道","自然災悔盡消磨"],"traditional":"","official":{"功名":"天不負人，修為必吉","行人":"相逢知己，切磋琢磨","婚姻":"好事多磨，守正得吉","官司":"正直無私，立身不敗","丁口":"修德行仁，家門吉慶","生意":"小心勤力，自然獲利","疾病":"虔誠作福，災悔消除","出行":"直道而行，無往不利","失物":"從前疏失，今後小心","田畜":"田財未旺，須得人和"},"modern":"籤詩像一句當頭棒喝：過去做事糊里糊塗，往後就要好好修正琢磨；只要一心走正道，災禍悔恨自然慢慢消散。這是一支「改過自新」的籤——運勢好壞掌握在自己手上，天不負苦心人。核心提醒：別再重蹈舊模式，從今天起認真、正直地做，局面就會翻轉。","categories":{"愛情婚姻":"好事多磨，過去的相處方式若有糊塗處就趁現在調整；守正以待、真誠經營，感情終能落定。","事業工作":"檢討先前的疏漏，做事上緊發條、走正路，天不負人；踏實修正後，事業自然轉吉。","財運":"小心勤力、自然獲利——財運不靠僥倖，靠的是收起散漫、認真記帳與經營；改掉糊塗帳，錢就留得住。","健康":"把過去傷身的習慣改掉，配合虔誠靜心的調養，災悔可消；身體會誠實回報你的自律。","考試學業":"過去讀書若不得法，現在切磋琢磨還來得及；修正方法、專心一志，努力必有回報。","訴訟糾紛":"正直無私、立身不敗：只要行得正、不耍手段，就立於不敗之地；誠實面對，是最好的辯護。","失物行人":"從前的疏失就讓它過去，今後收存財物多加小心即可；等候的人可望遇上知己般的重逢，彼此切磋、關係更進一步。"}},
  {"id":55,"name":"","level":"中","poem":["千倉米粟積如山","分惠飢貧事不難","勸子殷勤培善果","盛衰興廢本循環"],"traditional":"","official":{"功名":"幸福富貴，尤易修為","行人":"故人千里，攜手相逢","婚姻":"成家立業，主得內助","官司":"得意之時，須留後步","丁口":"飽暖不滛，自然安泰","生意":"交易公平，自然獲利","疾病":"積德保身，消災解厄","出行":"出門順利，宜結良緣","失物":"偶有遺失，不必追求","田畜":"好事多作，庶物繁昌"},"modern":"籤詩描寫千倉米粟堆積如山，分一些救濟飢貧並不困難；並勸人殷勤培植善果，因為盛衰興廢本是循環。這是一支「富而好施」的籤——你目前或即將處在豐足的位置，但好景會輪轉，唯有惜福行善能讓福氣延續。核心提醒：得意時多給人留餘地、多做好事，就是替自己存糧。","categories":{"愛情婚姻":"成家立業有內助之福，另一半是你的好幫手；懂得感謝與分享的家庭，日子越過越穩。","事業工作":"事業豐收在望，但盛衰循環是常態；順境時廣結善緣、善待夥伴與下屬，就是替未來的低潮買保險。","財運":"交易公平、自然獲利——正派經營財源穩固；行有餘力回饋社會，捨出去的會以福氣的形式回來。","健康":"身體大致安泰，飽暖之餘生活節制、不放縱，就是最好的保養；多行善事，心寬體自安。","考試學業":"處在資源與福分都不錯的位置，更該珍惜機會用功；學有餘力不妨幫助同儕，教學相長對自己也有益。","訴訟糾紛":"官方提醒「得意之時，須留後步」——即使占上風也別趕盡殺絕，留餘地的和解對你最有利。","失物行人":"偶有小遺失，不必執著追討，就當結個善緣、破小財消災；等候的人雖在千里，可望攜手相逢。"}},
  {"id":56,"name":"","level":"上","poem":["種得藍田璧一雙","鳳凰相感為翱翔","貴人自有非常遇","代代兒孫保吉昌"],"traditional":"","official":{"功名":"富貴福澤，源遠流長","行人":"好音將至，相遇非遥","婚姻":"宜室宜家，多子多孫","官司":"貴人扶持，事都如意","丁口":"吉人天相，閤門喜慶","生意":"時來運到，勤必如意","疾病":"指日痊癒，且有後福","出行":"利有攸往，遇合非常","失物":"去而復來，失去復得","田畜":"門廳吉慶，大小咸宜"},"modern":"籤詩滿是喜氣：藍田種玉得璧一雙、鳳凰相感雙雙翱翔，又有貴人帶來非比尋常的際遇，福澤綿延到代代兒孫。這是一支姻緣與家運俱佳的上籤，尤其利於嫁娶、添丁與家族長遠之事。提醒是福分深厚更要好好耕耘，善待身邊人，讓吉昌真正傳承下去。","categories":{"愛情婚姻":"鳳凰于飛、宜室宜家，是求姻緣的絕佳好籤；論及婚嫁大吉，婚後家庭和樂、子孫繁盛可期。","事業工作":"時來運到，加上貴人帶來非常的際遇，事業可望更上層樓；記得勤字訣，機會來了要接得住。","財運":"如藍田種玉，播下的種子會長成寶——投資與經營時運正旺，勤奮耕耘必能如意。","健康":"病者指日痊癒、且有後福；安心調養，不必過度憂慮。","考試學業":"富貴福澤、源遠流長，考運上乘；穩定發揮就有好結果，這份努力也會成為長遠發展的基石。","訴訟糾紛":"貴人扶持、事都如意，糾紛可望順利化解；坦然應對，結果會朝對你有利的方向走。","失物行人":"失物有去而復來之象，耐心尋找或等候，多半能物歸原主；等候的人好音將至，重逢不遠。"}},
  {"id":57,"name":"","level":"中","poem":["生平冷淡知音少","靜養根苗葆素真","共羨一枝黃菊好","秋深籬落自芳芬"],"traditional":"","official":{"功名":"盡人待天，後福耐久","行人":"雁足傳書，秋期必到","婚姻":"休圖早就，晚節方佳","官司":"自信無慚，有屈必伸","丁口":"家室平安，秋冬更吉","生意":"安心靜守，利息必多","疾病":"保養精神，交秋即癒","出行":"桂菊陽月，一路亨通","失物":"謹慎小心，得免多失","田畜":"春夏平平，秋來大利"},"modern":"籤詩以秋菊自況：平生淡泊、知音不多，只是靜靜涵養根苗、保全本真；待到深秋，籬邊一枝黃菊自然芬芳，眾人稱羨。這是一支「大器晚成」的籤——不必羨慕早開的花，你的好時節在秋後。核心提醒：耐得住寂寞、守得住本色，時候到了自然被看見。","categories":{"愛情婚姻":"姻緣不宜貪早求快，晚一點成的緣分反而穩固長久；把自己活好，對的人自會欣賞你的本色。","事業工作":"盡人事、待天時，你的後勁比別人耐久；不必急著搶鋒頭，默默累積實力，秋後自有你的舞台。","財運":"安心靜守、利息必多——財富走細水長流路線；春夏平平不用慌，秋天起收益明顯轉旺。","健康":"重點在保養精神、避免耗損，靜養勝過猛補；入秋之後身體可望明顯好轉。","考試學業":"像養根苗一樣養實力，一時沒被看見不代表白費；沉住氣持續累積，秋後的考試或成果發表正是你綻放的時候。","訴訟糾紛":"只要自信無愧於心，受的委屈終會伸張；不必急著辯個你死我活，時間會還你公道。","失物行人":"平日謹慎小心，就能免去多數損失，失物也往安靜角落找找；等候的人如鴻雁傳書，秋天必有消息到來。"}},
  {"id":58,"name":"","level":"上","poem":["四月十月風浪平","告君際遇在庚辛","凡事須循天理去","自然家室得康寧"],"traditional":"","official":{"功名":"安心向善，必獲際遇","行人":"好音重重，遇合不遠","婚姻":"成家安穩，西方際遇","官司":"際遇貴人，自然無浪","丁口":"存心行善，合家平安","生意":"梅陽月吉，得利更多","疾病":"盡心祈禱，自可痊安","出行":"出門平穩，當有際遇","失物":"向西尋覓，定然可遇","田畜":"春秋平平，夏冬景佳"},"modern":"籤詩報出明確的時點：四月與十月風浪平靜，際遇應在「庚辛」（庚辛之日或西方）；只要凡事順著天理去做，家宅自然安康。這是一支平穩踏實的上籤——好機會有其時、有其方，強求不如守正等候。核心提醒：把心放正、按天理行事，該來的際遇不會漏掉你。","categories":{"愛情婚姻":"成家安穩之象，緣分可能來自西方或姓氏、方位與「庚辛、金」有關的機緣；以誠相待，婚姻平順長久。","事業工作":"安心向善、必獲際遇——按規矩做事就會被看見；農曆四月與十月前後是推進大事的好時點。","財運":"官方批註指「梅陽月吉」（冬春之際尤佳），求財得利更多；順著時節布局，不必躁進。","健康":"誠心調養、安分作息，自可痊癒平安；心安是最好的藥引。","考試學業":"循著正道踏實準備，必獲際遇；報名、應試若能落在四月或十月前後的檔期，更為有利。","訴訟糾紛":"有貴人際遇相助，風浪自然平息；依理依法處理，不走旁門左道，結果自然安穩。","失物行人":"失物往西邊方向尋找，很有機會找回；等候的人好消息接連而來，相聚的日子不遠了。"}},
  {"id":59,"name":"","level":"中","poem":["不為工賈不為農","黃卷青燈自苦攻","若問終身休咎事","試看龍虎與雲風"],"traditional":"","official":{"功名":"際會風雲，功名大顯","行人":"若問行踪，寅辰必到","婚姻":"辛苦成家，遇合得意","官司":"福星拱照，所向得利","丁口":"春色盈門，平安為福","生意":"苦心經營，必獲大利","疾病":"終身平善，疾危消除","出行":"遇在寅辰，利有攸往","失物":"運際昌期，自無損失","田畜":"以長以養，孳息豐盈"},"modern":"籤詩刻畫一位不務工商農事、只在黃卷青燈下苦讀的人，終身吉凶就看能否等到龍虎風雲際會的那一刻。這是一支「苦讀待時」的籤——你走的是厚積薄發的路，辛苦是必經的本錢，風雲一到便功名大顯。核心提醒：別懷疑自己選的路，把苦功下足，時機（寅辰之年月日）自會給你答案。","categories":{"愛情婚姻":"辛苦成家、遇合得意——這段感情要靠奮鬥打底，但熬出來的家最經得起考驗，另一半會與你共苦同甘。","事業工作":"際會風雲、功名大顯：專業與資歷累積到位後，會有一飛沖天的機會；眼下的苦心經營都不會白費。","財運":"苦心經營、必獲大利——財富來自長期深耕而非短線投機；耐心把本業做深，回報相當可觀。","健康":"終身平善、疾危可消，不必過憂；只是苦讀苦拚之餘，記得留時間休息，別把身體當成本錢燒。","考試學業":"這是為讀書人量身打造的好籤：黃卷青燈的苦功終將換來金榜題名；堅持到底，寅、辰的年月是你的關鍵時點。","訴訟糾紛":"福星拱照、所向得利，是非糾紛可望順利化解；備妥事證、按程序走，結果對你有利。","失物行人":"運勢正處昌盛期，財物自然無甚損失，安心即可；等候的人在寅日或辰日（或寅辰之月）必到，耐心稍候。"}},
  {"id":60,"name":"","level":"中","poem":["常憑寶劍辟妖邪","十五年來事足誇","此去更宜韜晦好","磽磽易缺理無差"],"traditional":"","official":{"功名":"利就名成，急流勇退","行人":"音信稀疏，只看望日","婚姻":"事有反覆，且恐損失","官司":"退讓一步，可以無憂","丁口":"家室平平，幸保無事","生意":"一向穩足，速宜保守","疾病":"勞心勞力，須當保養","出行":"只宜安份，不可遠行","失物":"步步小心，須防失脫","田畜":"田財牧養，後不如前"},"modern":"籤詩回顧一路仗劍辟邪、十五年來成績足以自豪，但話鋒一轉：今後更該韜光養晦，因為太過剛硬的東西容易缺損，這是不變的道理。這是一支「功成宜退」的籤——過去的好表現是真的，但接下來的關鍵字是收斂與保守。核心提醒：見好就收、鋒芒內藏，守成比再攻更重要。","categories":{"愛情婚姻":"感情恐有反覆波折、甚至損耗之象；此時別逞強爭勝，收起銳氣、多退讓體諒，才能把關係穩住。","事業工作":"利就名成之後，官方批註直言「急流勇退」——擴張暫緩、鋒頭少出，把既有成果顧好，就是此刻最聰明的策略。","財運":"生意一向穩健，但現在該轉守勢：獲利落袋為安、避免新的大額冒險，保守就是最好的財技。","健康":"多年勞心勞力，身體的本該還了；放慢步調、認真保養，別再硬撐透支。","考試學業":"過去的成績值得肯定，但別自恃而輕敵；低調沉潛、穩穩複習，守住水準就是勝利。","訴訟糾紛":"退讓一步、可以無憂——這支籤明白勸和不勸戰；姿態放軟、適度讓利，糾紛就能平安落幕。","失物行人":"近期須步步小心、提防失竊遺落，貴重物品少帶出門；等候的人音信稀疏，約在農曆十五（望日）前後才有消息。"}},
  {"id":61,"name":"","level":"上","poem":["熟讀黃庭愛學仙","果然遇得好姻緣","秋風吹墮月中桂","看汝飛昇上九天"],"traditional":"","official":{"功名":"秋風報喜，必有好音","行人":"天緣湊巧，遇在目前","婚姻":"姻緣和合，且得佳麗","官司":"大合官情，所向無屈","丁口":"財喜臨門，家人有慶","生意":"財氣滿足，立秋大利","疾病":"占遇升騰，於病不利","出行":"順風揚帆，大有際遇","失物":"追尋可遇，失物當還","田畜":"孳生蕃茂，秋來得利"},"modern":"這支籤描寫一個人熟讀道書、潛心修行，不但遇上好姻緣，還在秋風中折得月中丹桂，一路飛昇上九天——是長年用功終於開花結果的上籤。核心訊息是：你累積的努力已經到了收成的時刻，尤其入秋之後喜訊連連。唯獨要提醒，順境中仍要保持謙和，別因得意而鬆懈。","categories":{"愛情婚姻":"籤詩明說「果然遇得好姻緣」，單身者有機會遇到合適又出色的對象，有伴侶者感情和合，可以放心往前走。","事業工作":"秋風折桂、飛昇九天，象徵升遷、錄取或案子成功的好兆頭，之前的耕耘即將被看見，秋天前後尤其有好消息。","財運":"財氣充足，生意與投資都有斬獲，立秋之後獲利更明顯，是可以積極一點的時期。","健康":"這支籤唯一要留意的就是健康：升騰的意象對病情反而不利，若身體有狀況別拖延，及早就醫、好好調養，不可大意。","考試學業":"「秋風吹墮月中桂」正是金榜題名的意象，考運極佳，把準備做足，放榜時自然有好音。","訴訟糾紛":"情理都站在你這邊，事情發展順著你的方向走，依正規程序處理即可，不必過度擔憂。","失物行人":"失物用心追尋可以找回；等待的人天緣湊巧，可能近在眼前就會相逢。"}},
  {"id":62,"name":"","level":"下下","poem":["小智而今莫漫施","損人自損豈非痴","上天報應原無爽","風雨雷霆詎有私"],"traditional":"","official":{"功名":"營私自誤，莫問前程","行人":"天涯杳杳，音信沉沉","婚姻":"鑽謀不成，心勞日拙","官司":"私不勝理，曲難作直","丁口":"丁眷啾唧，旦夕呻吟","生意":"戕伐之後，難望敷榮","疾病":"疾已沉疴，醫藥無功","出行":"此去無緣，恐有阻礙","失物":"從此小心，免再失脫","田畜":"田園消耗，牧產蕭疏"},"modern":"這支籤直白告誡：耍小聰明、損人利己，最後傷到的其實是自己，天理報應像風雨雷霆一樣公正無私。抽到此籤，多半是目前的做法或念頭裡帶著算計，事情才處處不順。轉機在於立刻回到正道——放下捷徑與心機，踏實做事、誠實待人，運勢才有機會慢慢回穩。","categories":{"愛情婚姻":"感情勉強不來，越用手段經營越是心力交瘁；先回歸真誠，把自己整理好，緣分才有空間出現。","事業工作":"目前不宜鑽營求進，走偏門只會自誤前程；先停下腳步檢視方向，改用正派踏實的方式重新累積。","財運":"元氣受損之後短期難以回升，不宜擴張或投機；守住本業、減少開銷，先止血再談獲利。","健康":"病況偏沉重、恢復較慢，別只靠偏方硬撐，務必配合正規治療、耐心調養，同時調整作息與心態。","考試學業":"投機取巧難有成果，這段時間成績不易突破；與其找捷徑，不如回到基本功，慢慢把底子補起來。","訴訟糾紛":"理虧的一方硬拗也拗不直，強爭只會更不利；誠實面對、盡早和解或止損，是眼前最好的出路。","失物行人":"遺失的東西恐怕難以尋回，重點是從此提高警覺、避免再度失脫；遠方的人音信沉寂，暫時聯繫不上，需要耐心等候。"}},
  {"id":63,"name":"","level":"中","poem":["我今與汝說分明","此去崎嶇路不平","救得難中人一個","即憑陰騭免災生"],"traditional":"","official":{"功名":"前程艱難，積德為先","行人":"水遠山高，音信難通","婚姻":"事多阻隔，且自隨緣","官司":"責己恕人，可保平安","丁口":"家人口舌，時有災星","生意":"不思獨善，自得平安","疾病":"病勢多險，虔誠祈求","出行":"道失平安，步履艱險","失物":"小心防閑，可免失脫","田畜":"命途不良，心多煩惱"},"modern":"籤詩坦白告訴你：接下來這段路崎嶇不平，但只要在難處中拉別人一把、積下陰德，就能憑這份善心化解災厄。這支籤的重點不在運氣好壞，而在你怎麼做人——多行善、多體諒，路再難也走得過去。遇事先助人、先反省自己，是這段時間最好的護身符。","categories":{"愛情婚姻":"感情路上阻隔較多，急也急不來；順其自然、以善意相待，該是你的緣分不會跑掉。","事業工作":"前程有些顛簸，先別急著求快，把品行與口碑顧好；肯幫同事、肯分擔的人，路會越走越開。","財運":"別只想著自己賺，肯與人分享、不貪獨利，財務反而平穩；投機冒進則容易生波折。","健康":"病勢有些風險，除了認真治療，也保持虔誠安定的心；家人互相照應，能平安度過。","考試學業":"考運普通、過程辛苦，與其求僥倖不如穩紮穩打；平日多助人、心存善念，臨場反而順。","訴訟糾紛":"多檢討自己、寬待對方，願意退一步就能保平安；得理不饒人只會讓事情更僵。","失物行人":"東西還沒丟的要提早防範，小心保管就能免於失脫；遠方的人山高水遠、音訊難通，需要多點耐心。"}},
  {"id":64,"name":"","level":"中下","poem":["爭名奪利竟何如","鏡裏看花總是虛","處世惟存忠厚好","閉門安樂享豐餘"],"traditional":"","official":{"功名":"富貴在天，只宜守舊","行人":"行人阻滯，消息非真","婚姻":"莫羨虛花，且宜守舊","官司":"退讓平安，進則有難","丁口":"雖然多事，幸得平安","生意":"勞心費力，名利皆虛","疾病":"尚未痊安，且宜靜養","出行":"徒然跋涉，且賦歸來","失物":"運犯破耗，須防失財","田畜":"眼前看好，終屬空虛"},"modern":"爭名奪利到頭來像鏡中看花，一場空；不如存心忠厚、關起門來安享現有的豐足。這支籤提醒你：眼前看似誘人的機會多半是虛花，追下去徒勞心力。此刻最好的策略是守成——珍惜手上已有的，待人厚道，平安就是福。","categories":{"愛情婚姻":"別羨慕外面的花花世界，也別被表面條件迷惑；守住現有的感情、安分經營，比追求虛華可靠得多。","事業工作":"富貴自有定數，目前只宜守住本職，不宜跳槽躁進或爭功；把分內事做好，安穩就是收穫。","財運":"勞心費力去追的利多半是空的，投資擴張都先緩一緩；防破財、守住現有積蓄才是重點。","健康":"身體尚未完全復原，急不得；靜養休息、減少奔波操勞，慢慢調理才會好。","考試學業":"求好高騖遠的目標容易落空，先把眼前的課業穩住；踏實累積，比追排名虛名更有意義。","訴訟糾紛":"退讓則平安，硬進則有難；能和解就和解，別為了爭一口氣把自己捲得更深。","失物行人":"近期運帶破耗，錢財物品要特別看緊；遠方的人行程受阻，傳來的消息未必屬實，先別盡信。"}},
  {"id":65,"name":"","level":"中","poem":["褻瀆三光造孽多","汝今求禱歎無因","欲逃此日風波險","改過虔誠奉斗真"],"traditional":"","official":{"功名":"何須奢望，急於自省","行人":"雲海茫茫，無由相見","婚姻":"天緣不湊，人力空勞","官司":"急宜自保，爭則有悔","丁口":"家眷啾唧，作福保安","生意":"莫求利息，且保平安","疾病":"命途危險，虔誠祈求","出行":"閉門守舊，不必遠行","失物":"運蹇時來，謹防失脫","田畜":"消耗日多，生息不旺"},"modern":"籤詩說過去輕慢了天地神明、累積了過失，如今臨時求禱難有感應；要躲過眼前的風波，唯有真心改過、虔誠修持。這支籤的訊息很清楚：問題出在自己過去的言行，向外求不如向內修。誠實面對錯誤、認真改正，風波自然有化解的一天。","categories":{"愛情婚姻":"目前天時不湊，勉強撮合只是白費力氣；先把自己的心態與言行調整好，緣分的門才會重新打開。","事業工作":"先別奢望升遷或大突破，眼前最要緊的是自我檢討；把過去的疏失補正，根基穩了再談前程。","財運":"這段時間別想著獲利，能保本、保平安就是贏；投資與擴張都先停看聽。","健康":"健康有風險訊號，除了虔心調養，更要徹底改掉傷身的習慣；改過就是最好的藥方。","考試學業":"與其臨時抱佛腳，不如老實檢討讀書方法哪裡出了問題；從根本改起，下一次才有勝算。","訴訟糾紛":"此時爭訟必有後悔，趕快以自保為上；能退則退、能和則和，別把事態擴大。","失物行人":"運勢正低，錢財物品要謹慎防範失脫；遠方的人如隔雲海，暫時難有相見的消息。"}},
  {"id":66,"name":"","level":"下下","poem":["陰謀詭計日益精","神目如電雷霆驚","人有千算天一算","自作自受最分明"],"traditional":"","official":{"功名":"痴心妄想，一事無成","行人":"時運不通，事事阻隔","婚姻":"枉費心機，事難成就","官司":"天網恢恢，無從逃避","丁口":"自作不善，必有災殃","生意":"命窮財盡，愈算愈拙","疾病":"自絕於天，祈求無益","出行":"風波不測，蹈險徒勞","失物":"財聚人怨，破損該然","田畜":"時運不通，事事相左"},"modern":"籤詩警示：算計越精，天看得越清——「人有千算天一算」，機關算盡終究是自作自受。抽到此籤，代表眼前的路若靠心機與投機去走，注定行不通。唯一的轉圜是徹底放下算計：老實面對現況、該認錯就認錯、該補救就補救，把心思用回正途，才能讓事情慢慢止跌。","categories":{"愛情婚姻":"用心機得來的感情留不住，越算計越難成；不如坦白真誠，成不成都讓彼此好聚好散。","事業工作":"痴心妄想、走捷徑都難有成果；先停止任何取巧的操作，回到本分把基礎重建起來。","財運":"越精打細算越是失算，此時進場投資或擴大生意都極為不利；守住現金、別再加碼是上策。","健康":"身心俱疲時別再硬撐或諱疾忌醫，放下執念、配合治療、好好休養，才是給自己的活路。","考試學業":"作弊或投機都是死路，成績也難靠運氣；這段時間老老實實打底，才可能翻身。","訴訟糾紛":"天網恢恢，理虧的部分躲不掉；越早坦承、和解、止損，付出的代價越小。","失物行人":"失物尋回的機會渺茫，就當破財消災、記取教訓；遠方的人時運不通、處處受阻，短期難有音訊。"}},
  {"id":67,"name":"","level":"中","poem":["暑月途中熱不勝","忽沾雨露頓心清","勸君更俟涼風動","管取飄飄兩腋輕"],"traditional":"","official":{"功名":"勸汝安心，秋風報喜","行人":"音信已通，萍踪可合","婚姻":"清淡為佳，趨炎則否","官司":"不須著急，可保平安","丁口":"夏防小災，秋季順利","生意":"夏季平平，秋來大利","疾病":"用心保養，自能復元","出行":"春夏未佳，秋冬迪吉","失物":"目前雖失，終久返還","田畜":"秋前未佳，秋後順利"},"modern":"大熱天趕路熱得受不了，忽然一陣雨露讓人心頭一涼；籤詩勸你再等等，等秋天涼風吹起，自然一身輕快。這是一支「時候未到、快到了」的籤：眼前的悶熱與煎熬只是過渡，不必硬衝，撐過夏天、等到秋涼，事情就會豁然開朗。","categories":{"愛情婚姻":"感情以平淡真誠為佳，別攀附條件好看但華而不實的對象；細水長流的相處，走得才遠。","事業工作":"先安下心把手邊事做穩，秋天前後會有好消息；現在急著求表現，不如等時機成熟再出手。","財運":"夏季財運平平，入秋後明顯轉旺；上半年守、下半年攻，節奏抓對就有利可圖。","健康":"身體像暑熱中人，需要的是休息與調養；用心保養、別再耗損，自然能恢復元氣。","考試學業":"「秋風報喜」，秋天的考試或放榜有望傳來佳音；眼前先耐住性子，把該讀的讀完。","訴訟糾紛":"不必著急，事情不會惡化；按部就班處理，時間站在你這邊，可保平安。","失物行人":"失物眼前雖找不到，日後終會物歸原主；遠方的人已有音訊，重逢有望。"}},
  {"id":68,"name":"","level":"中中","poem":["忽見蛟龍起海中","雲騰致雨浪兼風","善人遇此心安定","庸俗相逢膽戰忡"],"traditional":"","official":{"功名":"先難後進，端在修為","行人":"路多驚險，音信遲滯","婚姻":"事不安穩，切莫妄求","官司":"自問無漸，方得安穩","丁口":"雖有啾唧，可無大害","生意":"守己待時，可免疑慮","疾病":"病勢危險，作善求安","出行":"此去未利，恐有驚險","失物":"從此小心，自無差失","田畜":"現時不利，須防小災"},"modern":"海上忽然蛟龍翻騰、風急浪高——同樣的場面，心正的人安然自若，心虛的人膽戰心驚。這支籤說的是：眼前確實有風波，但吉凶取決於你平日的行事是否端正。問心無愧就穩得住；若有虧欠處，趁早補正，風浪過了自然平安。","categories":{"愛情婚姻":"感情目前不夠安穩，別強求進展或另起妄念；先靜下來，等關係中的風浪平息再說。","事業工作":"先難後進，成敗看自己的修為；此時守住本分、累積實力，等風頭過了再求突破。","財運":"守好現有的、耐心等待時機，就不必疑神疑鬼；貿然進場只會被浪打得心慌。","健康":"病勢有些兇險，除了積極治療，保持心安、多行善事，對病情的穩定有幫助。","考試學業":"過程會先辛苦一陣，實力到了自然過關；平日下的功夫，就是臨場最大的底氣。","訴訟糾紛":"自問無愧才站得穩；先確認自己這方站得住腳、把該備的證據備齊，就能安然度過。","失物行人":"從現在起小心保管，就不會再有差失；遠方的人路上多有驚險延誤，音訊會慢一些，先別過度擔心。"}},
  {"id":69,"name":"","level":"上","poem":["兒童竹馬喜相迎","共說神君吏治明","從此五風兼十雨","家家戶戶慶豐登"],"traditional":"","official":{"功名":"功成名就，事事如意","行人":"童子迎門，行人即至","婚姻":"姻緣和合，且喜多男","官司":"貴人有緣，諸事順利","丁口":"長幼咸寧，家門有慶","生意":"財源廣進，利路亨通","疾病":"吉人天相，解厄迎祥","出行":"順風揚帆，無往不利","失物":"陽長陰消，失而復得","田畜":"田園茂盛，六畜興旺"},"modern":"孩童騎著竹馬歡喜相迎，人人稱頌官府清明，從此風調雨順、家家戶戶慶豐收——這是一幅政通人和、皆大歡喜的太平景象，是難得的上籤。各方面都順遂如意，福氣正旺。提醒你在順境中持續行善、待人寬厚，讓這份好運走得長久。","categories":{"愛情婚姻":"姻緣和合、家庭美滿，論及婚嫁正是好時機，婚後更有添丁之喜。","事業工作":"功成名就、事事如意，是大展身手的時候；貴人在旁扶持，計畫可以放心推進。","財運":"財源廣進、利路亨通，正財偏財都旺；順勢經營，收成豐厚。","健康":"吉人天相，即使有小恙也能逢凶化吉；保持好習慣，身心都康泰。","考試學業":"考運大開，努力都能兌現成績；放手一搏，金榜有名。","訴訟糾紛":"有貴人相助，事情往對你有利的方向發展，可望順利落幕。","失物行人":"失物有失而復得之象，往光亮處、常走動的地方找找；遠方的人即將到來，好消息就在門口。"}},
  {"id":70,"name":"","level":"上","poem":["許汝三天有順風","開船平穩任西東","財源輻輳何須說","一路榮華命運通"],"traditional":"","official":{"功名":"功高名顯，一路榮華","行人":"三天以內，必有好音","婚姻":"天相吉人，和諧順意","官司":"一往順利，諸事稱心","丁口":"千祥雲集，百福會合","生意":"財運亨通，萬事如意","疾病":"福星拱照，可保平安","出行":"一路平安，四方順適","失物":"雖然失脫，去而復歸","田畜":"五穀豐登，牧畜咸亨"},"modern":"神明許你三天順風，開船出海平穩自在、任你東西；財源滾滾而來，一路榮華、命運亨通。這是行船遇順風的大吉之籤：眼前正是難得的順風期，想做的事放膽去做。提醒你把握時機、趁勢而為，但別因一路順遂而忘了基本的謹慎。","categories":{"愛情婚姻":"吉人天相，感情和諧順心；單身者有好緣分靠近，有伴者關係穩定甜蜜，可以規劃下一步。","事業工作":"功高名顯、一路榮華，正是衝刺的黃金期；提案、轉職、開創新局都順風順水。","財運":"財運亨通、財源輻輳，經營與投資都有好回報；順風時揚帆，收穫加倍。","健康":"福星拱照，身體可保平安；維持規律作息，小毛病也能很快復原。","考試學業":"考運正旺，準備的都考得出來；把握這段順風期全力衝刺，成績亮眼。","訴訟糾紛":"一路順利、諸事稱心，事情會朝對你有利的方向解決，不必憂心。","失物行人":"失物雖然一時不見，終會回到手上；遠方的人近日內就有好消息，甚至很快相見。"}},
  {"id":71,"name":"","level":"中","poem":["今年坐賈勝行商","莫向江頭趁野航","待得陽生冬至後","出門事事見榮昌"],"traditional":"","official":{"功名":"少年遲遲，晚景榮華","行人":"音信延滯，先花後果","婚姻":"正娶則吉，年底終成","官司":"不須急性，到尾完結","丁口":"平平過去，福自歸來","生意":"財氣平平，冬至大利","疾病":"一陽來復，方可全癒","出行":"目前未利，冬後方佳","失物":"不須尋覓，暗去明來","田畜":"春夏平平，冬勝於秋"},"modern":"今年開店坐守比出外行商有利，別急著到江邊搭上冒險的船；等冬至一陽初生之後再出門，事事都見榮昌。這是一支講「時機」的籤：上半年宜守不宜衝，冬至是轉運點。把眼前顧好、耐心蓄力，等時候到了再行動，自然水到渠成。","categories":{"愛情婚姻":"感情以正正當當、明媒正娶的方式進行最吉利；過程雖慢，年底前後有望開花結果。","事業工作":"年輕時或前期進展慢些不必氣餒，越到後面越見榮景；今年宜穩守崗位，冬至後再談新局。","財運":"上半年財氣平平，守住本業、別出遠門冒險投資；冬至之後財運明顯轉旺。","健康":"恢復需要時間，如同等待一陽來復；耐心調養到冬至前後，可望痊癒。","考試學業":"屬於大器晚成型，前期成績平平別灰心；穩紮穩打，年底或之後的考試會漸入佳境。","訴訟糾紛":"急不得，過程會拖一些，但最後能圓滿收尾；按程序走完，不必躁進。","失物行人":"失物不必費力翻找，時候到了會自己出現；遠方的人音訊延遲，先開花後結果，晚一點才有確切消息。"}},
  {"id":72,"name":"","level":"下下","poem":["貧窮疾病倍傷神","失脫官非聚一身","求著此籤無一可","閉門靜守渡秋春"],"traditional":"","official":{"功名":"不須妄求，百事難成","行人":"天涯杳杳，音信茫茫","婚姻":"命犯孤鸞，休生妄想","官司":"命運不通，動輙得咎","丁口":"孤苦伶仃，門衰戶落","生意":"勞心費力，總屬空虛","疾病":"時衰運退，凶多吉少","出行":"所向不利，不如閉門","失物":"窮愁失脫，雪上加霜","田畜":"田園荒廢，雞犬不寧"},"modern":"籤詩直言貧困、疾病、失物、官非齊聚一身，求到此籤諸事不宜，最好的做法是關起門來靜守，度過這段秋去春來的低潮。這支籤雖是下下籤，但它同時給了明確的出路：不是沒有未來，而是現在什麼都別強求。把生活縮小、把身心養好，低調撐過這一季，時間會帶來轉機。","categories":{"愛情婚姻":"目前緣分未到，勉強追求或倉促決定婚事都不宜；先照顧好自己的生活，等運勢回穩再談感情。","事業工作":"此時求職、創業、爭取表現都難有成果；守住現有位置、減少變動，蓄積實力等待下一個週期。","財運":"勞心費力也難有收穫，任何投資擴張都應暫停；量入為出、守住現金，是這段時間的首要任務。","健康":"運勢低時病痛也容易糾纏，務必及早就醫、認真治療，配合充分休養；別硬撐，健康是撐過低潮的本錢。","考試學業":"考運不佳，與其抱太高期待，不如把這段時間當作打底期；基礎補起來，來日方長。","訴訟糾紛":"此時動輒得咎，興訟或硬碰硬都非常不利；能和解就和解，能避就避，以脫身為上。","失物行人":"失物尋回的希望不大，先顧好還在手上的財物，別讓雪上加霜；遠方的人音訊茫茫，只能耐心等候。"}},
  {"id":73,"name":"","level":"中","poem":["故人寄我一封書","約去他鄉共販絲","若遇龍潭須謹慎","平安全仗佛扶持"],"traditional":"","official":{"功名":"祿運未通，須當守己","行人":"書信已通，相見不遠","婚姻":"姻緣遠覓，未利辰年","官司":"風波不測，終得平穩","丁口":"存心行善，保佑平安","生意":"財氣未足，須當靜守","疾病":"得過辰日，方保平安","出行":"前途謹慎，恐驚不穩","失物":"牧種未到，財氣平平","田畜":"牧種未到，財氣平平"},"modern":"老朋友寄來一封信，邀你到外地一起做買賣；機會是真的，但途中若遇上龍潭險處務必謹慎，平安還得靠神佛保佑、自己小心。這支籤說的是：眼前有值得一試的合作或機會，但不是坦途，關鍵處要放慢腳步、做足防範，穩紮穩打才能平安獲利。","categories":{"愛情婚姻":"姻緣可能在遠方或透過遠處的牽線出現，但今年（尤其辰年）時機未熟；不必急，讓關係慢慢醞釀。","事業工作":"有人邀約合作或新機會可以認真考慮，但祿運未全開，條件與風險要看清楚；謹慎評估後再上路。","財運":"財氣還不夠飽滿，宜靜守、小步走；合夥做生意可行，但關鍵環節務必謹慎，別押上全部身家。","健康":"病情過了關鍵期（辰日前後）就能穩定下來；期間細心照護、遵照醫囑，可保平安。","考試學業":"運勢尚未全通，別指望一步登天；穩住步調、把難關處多下功夫，成績會慢慢跟上。","訴訟糾紛":"過程會有風波與變數，但最終能平穩落幕；謹慎應對每個環節，別掉以輕心。","失物行人":"遠方的人書信已通，相見的日子不遠了；失物方面財氣平平，未必能尋回，先把心力放在顧好眼前。"}},
  {"id":74,"name":"","level":"上","poem":["與子當年有宿因","同舟共濟勝周親","若能更把真心托","添喜添財孰比倫"],"traditional":"","official":{"功名":"得遇知音，功成名就","行人":"同心會合，千里相逢","婚姻":"因親結親，財喜自旺","官司":"貴人相扶，官司得勝","丁口":"六親相和，添丁進財","生意":"用人勿疑，財源自足","疾病":"貴人出現，漸漸安好","出行":"同伴得人，出門有益","失物":"同居和好，失物可尋","田畜":"利息頻添，更勝往年"},"modern":"籤詩說你與對方前世有緣，同舟共濟的情誼勝過至親；若能再把真心託付，添喜又添財，無人能比。這是一支講「信任與合作」的上籤：好運來自身邊的夥伴與貴人，只要以誠相待、用人不疑，感情與財富都會跟著旺起來。","categories":{"愛情婚姻":"彼此像前世註定的緣分，親上加親、越走越旺；用真心交付對方，婚姻幸福又帶財喜。","事業工作":"得遇知音與好夥伴，是功成名就的關鍵；找對人合作、真心託付，事業自然起飛。","財運":"合夥經營用人勿疑，信任帶來財源；今年利息收益更勝往年，可以放心與人共事共利。","健康":"會遇到好醫師或貴人指點，病情漸漸好轉；安心配合治療，恢復指日可待。","考試學業":"遇到好老師、好同伴一起切磋，學業事半功倍；虛心請教，成果會超出預期。","訴訟糾紛":"有貴人出面相助，情勢對你有利，可望勝訴或圓滿解決；慎選可信賴的專業協助。","失物行人":"家人同心、和睦相處，失物有機會找回；遠方的人與你心意相通，千里也能相逢。"}},
  {"id":75,"name":"","level":"中","poem":["萬里長空一雁飛","欲求同侶悵無依","勸君且就蘆洲宿","等待秋風振羽儀"],"traditional":"","official":{"功名":"眼前未到，靜守待時","行人":"故人天遠，且待秋期","婚姻":"今年未利，且待明春","官司":"該行則行，可止則止","丁口":"家口未寧，有小啾唧","生意":"財運未通，安心待時","疾病":"認真保養，秋涼自痊","出行":"守分守己，不可漫行","失物":"運當損失，應破小財","田畜":"田畜未旺，收成小利"},"modern":"萬里長空中一隻孤雁飛翔，想找同伴卻悵然無依；籤詩勸你先在蘆洲棲息，等秋風起再振翅高飛。這支籤描寫的是暫時的孤單與等待：現在不是強出頭的時候，安頓好自己、養精蓄銳，時機一到自然能展翅。","categories":{"愛情婚姻":"今年姻緣尚未成熟，像孤雁尋侶急不得；先充實自己，明年春天以後機會較好。","事業工作":"機會眼前還沒到，靜守待時最穩當；別羨慕別人飛得高，把羽翼養壯，秋後自有你的天空。","財運":"財運未通，此時進場多半徒勞；安心守成、控制支出，等風向轉了再出手。","健康":"認真保養、別過度操勞，天氣轉涼後身體自然痊癒；急著復出反而傷身。","考試學業":"眼前成績還看不到突破，不必焦慮；按部就班累積，秋天前後會迎來明顯的進步。","訴訟糾紛":"該進行就進行、能停就停，彈性應對；不硬拚、不戀戰，見好就收最安全。","失物行人":"近期運帶小損失，遺失的東西就當破小財消災，別過度追究；遠方的故人音訊要等到秋天才明朗。"}},
  {"id":76,"name":"","level":"上中","poem":["萬頃波濤一葉舟","安如磐石自夷猶","吉人自有神明佑","何必臨危事禱求"],"traditional":"","official":{"功名":"福祿天成，全不費力","行人":"遠人在途，相見不遠","婚姻":"遠娶更宜，且得佳婦","官司":"神力扶持，安穩無事","丁口":"家門順利，人口平安","生意":"隨意經營，財源興旺","疾病":"吉人天相，不須介懷","出行":"順風揚帆，諸事順利","失物":"故物無恙，不求自歸","田畜":"牧畜興旺，田財茂盛"},"modern":"萬頃波濤中的一葉小舟，卻安穩如磐石、從容自在——因為吉人自有神明保佑，何必等到臨危才來祈求。這支籤是對你平日為人的肯定：心正行善的人，再大的風浪也傷不了。眼前縱有波折，不必慌張，照你原本的正道走，自然逢凶化吉。","categories":{"愛情婚姻":"姻緣天成，即使對象來自遠方也很合適，能得到體貼賢慧的伴侶；以平常心相待，感情自然穩固。","事業工作":"福祿天成、不必費力強求，外界再動盪你的位置依然穩固；照自己的節奏做事就好。","財運":"隨意經營都有財源，不必汲汲營營；穩健布局，收穫自然興旺。","健康":"吉人天相，健康不須過度擔憂；維持平日的好習慣，小病小痛都能安然度過。","考試學業":"平日累積的實力就是你的定海神針，臨場不必緊張；正常發揮，成績水到渠成。","訴訟糾紛":"有如神助般安穩無事，情勢會自然朝有利方向平息；不必四處奔走求援。","失物行人":"失物完好無損，不用刻意去找，會自己回到你手上；遠方的人已在路上，相見不遠。"}},
  {"id":77,"name":"","level":"中","poem":["欲知此去真消息","說汝聽時膽莫寒","過得雪山千萬疊","別開生面與君看"],"traditional":"","official":{"功名":"無苦不成，先難後易","行人":"欲尋消息，冬盡交春","婚姻":"眼前未到，到底還佳","官司":"事多不測，後可無妨","丁口":"家有疾危，危而得安","生意":"否極泰來，方得如意","疾病":"病勢危險，終保平安","出行":"跋涉險阻，苦盡甘來","失物":"運多破財，小心謹慎","田畜":"今歲未佳，過冬乃佳"},"modern":"籤詩先給你打預防針：接下來的路要翻過千萬疊雪山，聽了別膽寒——因為翻過去之後，就是一片別開生面的新天地。這是一支「先苦後甘」的籤：眼前的難關是真的，但結局是好的。咬牙撐過最難的這一段，柳暗花明就在山的另一頭。","categories":{"愛情婚姻":"感情眼前還看不到結果，過程也有波折，但走到最後是好的；別在半路放棄，耐心經營終能修成正果。","事業工作":"無苦不成、先難後易，現在的辛苦都是必經的雪山；撐過這段爬坡期，局面會煥然一新。","財運":"否極泰來之象，眼前財務吃緊只是過程；守穩底線、熬過寒冬，之後才見起色。","健康":"病勢一度險峻，但終能轉危為安；積極治療、別被過程嚇退，過了這關就海闊天空。","考試學業":"準備過程加倍辛苦，正是翻越雪山的階段；肯下苦功的人，最後會看到別人看不到的風景。","訴訟糾紛":"過程變數多、一波三折，但最終不會有大礙；步步為營走完程序，結果可以放心。","失物行人":"近期運帶破財，財物要格外小心保管；遠方的人要等冬去春來才有確切消息，先安心等候。"}},
  {"id":78,"name":"","level":"上","poem":["龍宮貝闕最莊嚴","君去行商趁一帆","財積如山人共羨","到家正值燕呢喃"],"traditional":"","official":{"功名":"前程遠大，衣錦榮歸","行人":"行人大利，春來可到","婚姻":"主得妻才，兼繁子嗣","官司":"貴人相扶，諸事順利","丁口":"門戶清吉，更喜添丁","生意":"十分財氣，滿載而歸","疾病":"祈禱求安，春來自癒","出行":"到處順利，財氣充盈","失物":"去而復來，失可再得","田畜":"田宅興旺，六畜繁殖"},"modern":"龍宮寶殿莊嚴富麗，你乘著一帆順風出外經商，賺得財積如山、人人稱羨，回到家正是春燕呢喃的時節。這是一支出外發展、滿載而歸的大吉籤：放手去闖，外面的世界對你敞開；提醒你發達之後記得回饋家庭，富貴才圓滿。","categories":{"愛情婚姻":"有娶得賢妻良伴之象，婚姻美滿還有子嗣之喜；成家與事業可以並進，兩頭都旺。","事業工作":"前程遠大、衣錦榮歸，出外發展或開拓新市場大有可為；貴人扶持，放膽去做。","財運":"十分財氣、滿載而歸，經商投資都有豐厚回報；正是積極進取、擴大格局的好時機。","健康":"有小恙也不必憂心，安心調養、心存善念，春暖時節自然痊癒。","考試學業":"前程似錦，努力會換來亮眼的成績與榮耀；目標可以設高一點，你有本錢去爭取。","訴訟糾紛":"貴人相扶、諸事順利，紛爭可望順利化解，結果對你有利。","失物行人":"失物去而復返，還有機會找回來；遠方的人一路順利，春天前後就會帶著好消息回來。"}},
  {"id":79,"name":"","level":"上","poem":["紫誥黃封耀古今","祥雲擁護使星臨","太平景象神人悦","海若咸懷效順心"],"traditional":"","official":{"功名":"福祿壽全，功高名顯","行人":"喜信頻至，不日來臨","婚姻":"子貴夫榮，百年和合","官司":"貴人相扶，事事順遂","丁口":"竹林清吉，日報平安","生意":"財氣興旺，滿路異香","疾病":"神靈庇佑，身體康寧","出行":"吉星拱照，行必有利","失物":"不必追求，物當自出","田畜":"種竹養魚，利息加倍"},"modern":"皇帝的詔書金光耀眼，祥雲簇擁著天使降臨，一派太平景象，神人同悅、四海歸心——這是福祿壽俱全的大吉之籤。你的德行與努力得到上天嘉許，名望、財富、家庭樣樣圓滿。提醒你身在高處更要謙和惜福，這份榮耀才能長長久久。","categories":{"愛情婚姻":"夫榮子貴、百年好合之象，婚姻極為美滿；兩人互相成就，家運越來越興旺。","事業工作":"功高名顯、福祿壽全，是名利雙收的巔峰運勢；升遷、受表彰、接大任都水到渠成。","財運":"財氣興旺、一路飄香，經營投資皆有倍數回報；行有餘力不妨回饋，福上加福。","健康":"神靈庇佑、身體康寧，健康無虞；保持規律生活，福壽綿長。","考試學業":"有金榜題名、光耀門楣之象，考運極盛；全力以赴，成績會是眾人矚目的那一個。","訴訟糾紛":"貴人相扶、事事順遂，糾紛能圓滿化解，甚至因此贏得敬重。","失物行人":"失物不必費心追找，時候到了自己會出現；遠方的人喜訊頻傳，近日就會來到。"}},
  {"id":80,"name":"","level":"下下","poem":["前生逋欠我深知","此日相償數適宜","莫便生嗔兼悔恨","塞翁失馬未為奇"],"traditional":"","official":{"功名":"枉費心機，一無所就","行人":"音信虛無，孤踪寂寞","婚姻":"若問姻緣，有終則吉","官司":"命運乖違，諸事顛倒","丁口":"孤苦伶仃，窮愁潦倒","生意":"欲圖得利，反折其本","疾病":"自作之孽，悔恨已遲","出行":"所向不利，漂泊無依","失物":"前生所欠，今世償還","田畜":"如釜養魚，如湯潑雪"},"modern":"籤詩說這次的損失像是償還前世欠下的債，數目剛剛好；勸你別動怒、別悔恨——塞翁失馬，焉知非福。這支籤雖屬下下，講的卻是「放下」的智慧：眼前的失去強求不回，越執著越苦。把它當作一筆債的了結，心平氣和地止損、重新出發，禍事之後往往藏著轉機。","categories":{"愛情婚姻":"感情若有波折，別急著怨懟或硬留；能好好收尾、善始善終就是吉，放下執念才有新的開始。","事業工作":"此時強求功名只是白費心機，計畫多半落空；先接受現況、盤點損失，把心力留給下一個週期。","財運":"想賺反而折本，任何投資加碼都不宜；當前的虧損就當還債止損，守住剩下的本金最重要。","健康":"身體的狀況多與過去累積的習慣有關，與其懊悔不如立刻改變；戒掉傷身的行為、認真治療，猶未為晚。","考試學業":"這次考運不佳，結果可能不如預期；別困在悔恨裡，把失利當成調整方法的契機，下次再戰。","訴訟糾紛":"運勢乖違、爭訟只會事事顛倒；能和解就和解、能認賠就認賠，早點抽身就是止損。","失物行人":"失物尋回無望，就當償還一筆舊債、破財消災，別再耗神追究；遠方的人音訊全無，暫時只能各自安好。"}},
  {"id":81,"name":"","level":"中下","poem":["季子歸去意氣驕","家人匐伏畏雄豪","豈知富貴榮華事","壹似朝潮與暮潮"],"traditional":"","official":{"功名":"富貴不常，香消燈燼","行人":"音信將至，非朝即暮","婚姻":"勿論眼前，須防反覆","官司":"官斷無常，事多反覆","丁口":"勞瘁非常，眾人啾唧","生意":"財氣雖有，東得西失","疾病":"精神不固，癒亦難久","出行":"朝秦暮楚，去留不定","失物":"有聚必散，數所當然","田畜":"目前雖旺，難保常榮"},"modern":"籤詩借季子衣錦還鄉、家人敬畏的場面說：眼前的富貴風光，其實像早潮晚潮一樣，來得快也退得快。這支籤提醒你，此刻的順遂未必長久，得意時別驕縱，凡事留餘地、早做打算，潮水退時才站得穩。","categories":{"愛情婚姻":"眼前的甜蜜先別急著當定局，這段關係還有變數，多花時間觀察彼此，慢慢確認再往前走。","事業工作":"目前的成績有起有落，風光難保長久，不宜趁勢大舉擴張，穩紮穩打、守住基本盤比較實在。","財運":"財氣雖有，卻是東邊進、西邊出，進帳留不太住；控管開銷、避免大手筆投入，先求守成。","健康":"身體狀況起伏不定，就算好轉也別急著鬆懈，持續調養、規律作息，才不容易反覆。","考試學業":"成績容易忽好忽壞，一時的好表現靠不住，把基礎打穩、長期累積，比短期衝刺更重要。","訴訟糾紛":"情勢反覆難料，今天有利明天未必，別戀戰硬拚，能和解就和解，早點抽身為上。","失物行人":"等待的人消息快到了，早晚之間就有音訊；失物則聚散有時，找回的機會不大，別太掛心。"}},
  {"id":82,"name":"","level":"中","poem":["鴻雁來時汝運通","吳頭越尾好從容","更看明月圓如鏡","遇得神仙便御風"],"traditional":"","official":{"功名":"桂月空明，秋香得意","行人":"天邊鴻雁，相會有期","婚姻":"急難成就，緩得團圓","官司":"貴人有緣，自能順遂","丁口":"合門順利，秋冬更吉","生意":"春夏未利，秋冬甚佳","疾病":"從容保養，秋來必痊","出行":"若到蘇杭，諸事順利","失物":"近水尋覓，月望可逢","田畜":"田財有成，秋收富足"},"modern":"鴻雁飛來時運勢就通了，往來各地都能從容自在；等到明月圓滿如鏡，更有貴人相助、乘風而行。這支籤的關鍵在時機：眼前先別急，把自己準備好，等秋天月圓時節到來，事情自然水到渠成。","categories":{"愛情婚姻":"這段緣分急不得，越催越難成；放慢腳步慢慢經營，時候到了自然團圓美滿。","事業工作":"上半年進展平平不用氣餒，秋冬運勢明顯轉旺，還有貴人相助，先蓄力等時機。","財運":"春夏財運普通，別勉強求財；秋冬之後進帳轉佳，把資源留到對的時點再出手。","健康":"不必求速效，從容調養、按部就班，入秋之後可望痊癒，心情放寬最要緊。","考試學業":"有「秋闈得意」之象，秋天的考試特別有利；按進度穩穩準備，時候到了自能發揮。","訴訟糾紛":"有貴人緣，事情能順利化解；別急著硬碰硬，多借重可信的人從中協調。","失物行人":"失物往有水的地方找，月中前後有機會尋回；遠方的人相會有期，鴻雁捎信，不久就有消息。"}},
  {"id":83,"name":"","level":"上","poem":["萬里橋頭送客行","壹場辛苦不須論","憑將三寸蘇張舌","唾手功成獨讓君"],"traditional":"","official":{"功名":"吃盡辛苦，方得成名","行人":"行人得意，消息可通","婚姻":"先難後易，全仗良媒","官司":"雖逢勁敵，君當得勝","丁口":"好音時來，人口平安","生意":"起手艱難，收功大利","疾病":"病勢雖重，可保平安","出行":"客路艱難，必有際遇","失物":"運逢小耗，謹守無害","田畜":"畜牧田財，勤勞得利"},"modern":"萬里橋頭送人遠行，一路辛苦不必多說；但憑一張能言善道的嘴，功業唾手可得，最後成就歸你。這支籤是先苦後甘的格局：過程確實辛勞，只要肯溝通、善表達，堅持到底就能出頭。","categories":{"愛情婚姻":"先難後易，起頭波折多，但只要有好的媒人或朋友從中牽線撮合，這段姻緣終能成就。","事業工作":"起步艱難、吃足苦頭，但你的口才和溝通力是最大本錢；談判、提案多表現，最後成果豐厚。","財運":"賺錢的過程辛苦，起手不順別灰心，撐過前段，收尾獲利可觀，勤勞就有回報。","健康":"病勢看起來不輕，但終能平安度過；積極配合治療、耐心休養，會慢慢好轉。","考試學業":"吃盡辛苦方得成名——這一路要下真功夫，沒有捷徑，但努力不會白費，金榜有望。","訴訟糾紛":"對手雖強，你這方佔理；好好準備說法、據理力爭，最後勝算在你。","失物行人":"遠方的人一切順利，消息很快能通；失物屬小損，找回與否影響不大，看緊其餘財物即可。"}},
  {"id":84,"name":"","level":"中","poem":["青蚨盈萬積如坵","收拾無從歎不休","好把一繩穿貫去","教君怕足更何求"],"traditional":"","official":{"功名":"專心勤學，可保成名","行人":"一帆風順，送到行人","婚姻":"家道興隆，當得內助","官司":"認清道路，可合官情","丁口":"家庭安慶，不必多慮","生意":"財氣滿足，好好收成","疾病":"一心調養，自得安康","出行":"出門有財，祈神保佑","失物":"偶有遺失，指點尋歸","田畜":"生息豐餘，收成富足"},"modern":"錢財堆積如山丘，卻散亂得不知從何收拾；只要拿一條繩子把錢串起來，好好整頓，就會發現已經夠用，還求什麼呢。這支籤說你其實不缺福分，缺的是整理與知足：把手上的資源理清楚、專心守好，自然安穩富足。","categories":{"愛情婚姻":"家運正興，能得一位持家的好伴侶；珍惜身邊人、共同打理生活，感情越過越穩。","事業工作":"手上的機會和資源不少，別再貪多，把散落的事情收攏、專心做好一件，就能好好收成。","財運":"財氣充足，重點在理財：把收支帳目整頓清楚、化零為整，守住已有的就很富足。","健康":"沒有大礙，一心一意調養、別三心二意換方法，身體自然安康。","考試學業":"資質夠、材料也夠，就差專心；收心勤學、按部就班，成名有望。","訴訟糾紛":"把來龍去脈理清楚、照正規程序走，事情就能順利了結，不必繞路。","失物行人":"偶有遺失不用慌，會有人指點方向，循線可以找回；遠方的人一帆風順，平安歸來。"}},
  {"id":85,"name":"","level":"下下","poem":["命犯孤辰只合休","駌鴦兩下遂溪流","枯楊豈肯重生葉","風雨飄零空自愁"],"traditional":"","official":{"功名":"一生貧賤，名利皆空","行人":"星稀月落，夢影迷離","婚姻":"既鮮遇合，兼乏財丁","官司":"命運不通，事多荊棘","丁口":"門衰戶冷，孤苦伶仃","生意":"事業飄零，營生愈拙","疾病":"燈盡煙消，水盡山窮","出行":"東走西奔，棲身莫定","失物":"命犯破耗，自有失脫","田畜":"六賊搬運，雞犬不寧"},"modern":"籤詩說命逢孤辰、鴛鴦分飛順水流，枯楊難再發新葉，風雨中飄零自愁。這是支很低落的籤，說眼前確實是孤單艱難的時節；但籤是提醒不是判決——此刻不宜強求任何事，先把自己照顧好、保守度日、多找親友支持，沉潛蓄力，等這陣風雨過去再重新出發。","categories":{"愛情婚姻":"目前緣分淡薄，感情容易聚少離多；與其勉強挽留，不如先安頓好自己的心，緣分未到不必強求。","事業工作":"運勢低迷，越拚越使不上力；此時不宜創業或轉換跑道，守住現有的位置、充實自己，等待轉機。","財運":"有破耗之象，錢財容易流失；一切保守，不投資、不借貸、不作保，守住現金最重要。","健康":"身體亮紅燈，千萬別硬撐；務必及早就醫、認真治療休養，把健康擺在所有事情前面。","考試學業":"這次恐怕不如預期，但一次失利不代表永遠；先別自我否定，休整之後調整方法，來日再戰。","訴訟糾紛":"官司荊棘重重、對你不利；能和解就和解，及早止損抽身，別把心力耗在纏訟上。","失物行人":"失物有破耗之象，尋回機會渺茫，就當破財消災；遠方的人音訊迷離，暫時難有消息，只能耐心等。"}},
  {"id":86,"name":"","level":"下下","poem":["生長江河慣御船","誰知翻覆有多端","青龍若遇當無恙","白虎相冲心膽寒"],"traditional":"","official":{"功名":"妄想功名，反多驚險","行人":"行途多遲，逢辰可遇","婚姻":"事多反覆，且忌寅生","官司":"步步小心，恐防反覆","丁口":"家門未利，當有小災","生意":"故作誤為，經營不利","疾病":"病體反覆，須當小心","出行":"恃才妄行，心多驚險","失物":"指東話西，得失參半","田畜":"牧養遜前，田畜小利"},"modern":"在江河邊長大、駕船駕慣了的人，誰知道還是會翻船；遇上青龍吉星尚可平安，碰到白虎凶星就叫人心膽俱寒。這支籤警告的是「大意失荊州」：越是熟悉的事越容易輕忽出錯，凡事步步小心、別恃才妄行，謹慎就能避開大半風險。","categories":{"愛情婚姻":"感情反反覆覆、波折不少；別倉促定終身，也別自認很懂對方，多溝通、慢慢磨合再說。","事業工作":"最熟的業務反而最容易出包；別憑經驗抄捷徑或便宜行事，照規矩按部就班，可免大錯。","財運":"財運不穩，自作聰明的操作容易翻船；遠離高風險投資，老老實實守住本金。","健康":"病情容易反覆，好轉了也別大意；遵照醫囑、定期回診，小心呵護才能真正痊癒。","考試學業":"別好高騖遠、也別仗著底子好就輕敵；回到基本功、細心檢查，才不會在熟悉的題目上翻船。","訴訟糾紛":"情勢隨時可能反轉，步步都要小心；文件、程序都別馬虎，穩紮穩打防變數。","失物行人":"失物線索混亂、指東話西，找回一半機會；遠方的人途中多延誤，時機到了自能相見。"}},
  {"id":87,"name":"","level":"中中","poem":["長舌之言不可聽","謹防世上小人心","汝今問我凶和吉","同氣三人可斷金"],"traditional":"","official":{"功名":"欲求功名，先修倫常","行人":"同氣相求，行人即到","婚姻":"好謀棠棣，莫問姻緣","官司":"兄弟相和，可禦外侮","丁口":"家門和順，諸事平安","生意":"兄弟同心，黃土變金","疾病":"陰人見咎，早禳為佳","出行":"居家啾唧，出門有慶","失物":"閑言勿聽，同心可尋","田畜":"田宅平平，家和事興"},"modern":"搬弄是非的話不要聽，要提防世上的小人心；問吉凶嗎——一家人同心，力量可以斷金。這支籤的重點是「防讒言、靠團結」：外面的閒話少聽，把家人和夥伴的心聚在一起，自然逢凶化吉。","categories":{"愛情婚姻":"感情最怕外人閒言閒語挑撥；先把家人手足間的情分顧好，姻緣的事別急，也別讓流言動搖兩人的心。","事業工作":"兄弟同心、黃土變金——和夥伴齊心協力就能成事；當心搬弄是非的小人，重要決定親自求證。","財運":"獨力難成，合夥同心才能生財；帳目公開透明，別因閒話猜忌夥伴，和氣自然生財。","健康":"多半是心神不寧、思慮過重所致；放寬心、早點調理，有家人陪伴照應，慢慢就會好轉。","考試學業":"先把品行和本分顧好，功名自然有望；讀書環境單純點，別被同儕閒話分了心。","訴訟糾紛":"自家人先團結一致，對外才有力量；內部別先起口角，同心就能抵禦外侮。","失物行人":"別聽旁人瞎猜，家人一起靜下心找，失物可尋；遠方的人很快就到，不必擔憂。"}},
  {"id":88,"name":"","level":"上","poem":["有人販得洞庭紅","鉅萬財源頃刻通","男子運來難預料","今朝送汝一帆風"],"traditional":"","official":{"功名":"祿運亨通，功名得志","行人":"好音自至，頃刻相逢","婚姻":"助夫益子，諸事順利","官司":"貴人相扶，事事勝人","丁口":"家門順利，百事迪吉","生意":"財運亨通，諸事咸宜","疾病":"勿藥有喜，身體康安","出行":"利有攸往，出門大吉","失物":"財旺之時，可免失脫","田畜":"田財興旺，物畜豐餘"},"modern":"有人販運洞庭紅橘，鉅萬財源頃刻暢通；人的好運來時難以預料，今天就送你一帆順風。這是支難得的好籤，時運正旺、做什麼都順；把握這陣順風放手去做，但也記得好運難料，得利時留些餘裕、莫忘感恩。","categories":{"愛情婚姻":"感情順遂，彼此互相扶持、旺家旺運；已婚者家和事興，未婚者好對象近在眼前，可以主動一點。","事業工作":"祿運亨通、貴人相扶，正是大展身手的時候；想推的計畫、想爭取的位置，趁這波順風出手。","財運":"財運大開，經營買賣頃刻通達；該投入就投入，但賺得快也要存得住，別因順手而揮霍。","健康":"不藥而癒之象，身體無大礙；保持目前的好狀態，正常作息即可，不必多慮。","考試學業":"功名得志，考運正旺；照實力發揮就有好成績，志願可以放膽填高一點。","訴訟糾紛":"有貴人相助，事事勝人一籌；據理進行即可順利落幕，不必憂心。","失物行人":"正值財旺，失物多能免於損失，往常放的地方找找便有；遠方的人好消息將至，很快相逢。"}},
  {"id":89,"name":"","level":"中","poem":["東舍烹牛禱不靈","不如西舍點青燈","上天感應憑方寸","壹念精誠神鬼欽"],"traditional":"","official":{"功名":"存心向善，前程有望","行人":"若問音信，行踪未定","婚姻":"且宜隨緣，休生妄想","官司":"錢不可通，須憑理斷","丁口":"好憑方寸，自得平安","生意":"不敢妄求，自然平穩","疾病":"宜緩小刻，可保康安","出行":"大望難成，小就則可","失物":"急向西覓，大財難歸","田畜":"多求則拙，小畜無妨"},"modern":"東家殺牛大拜拜，祈禱卻不靈驗；不如西家只點一盞青燈，心誠就感動上天——神明看的是你的心，不是排場。這支籤要你回到「誠」字：不投機、不鋪張、不妄求，本本分分做事，一念精誠自有感應。","categories":{"愛情婚姻":"感情宜隨緣，不要有不切實際的幻想；真誠相待、細水長流，比刻意追求更能修成正果。","事業工作":"不必好大喜功，把分內事做實在，自然平穩有進；靠排場和關係撐起來的，反而不長久。","財運":"不貪不妄求，財路自然平穩；小財可得，大財勿強求，賺實在錢最安穩。","健康":"急不得，放慢步調細心調養，可保安康；與其亂投偏方，不如安分靜養。","考試學業":"存心端正、踏實用功，前程就有望；想靠猜題或運氣走捷徑，不如一步步把書讀通。","訴訟糾紛":"這場糾紛錢打不通門路，只能憑道理裁斷；行得正就不怕，切莫想私下疏通。","失物行人":"失物趕快往西邊找，小東西找得回，值錢的難歸；遠方的人行蹤未定，音訊還要再等等。"}},
  {"id":90,"name":"","level":"中中","poem":["梓匠輪輿一事專","養家糊口足盤餐","莫生奢望思遷業","惹得風波反不安"],"traditional":"","official":{"功名":"好求溫飽，莫問前程","行人":"既得旅食，莫便思歸","婚姻":"只宜低就，莫攀高門","官司":"勿思爭執，恐惹風波","丁口":"但能知足，可保平安","生意":"改舊必失，守舊則安","疾病":"信舊醫藥，自能安順","出行":"安份為佳，出門多阻","失物":"失物雖回，餘悔未絕","田畜":"不必多求，平平乃過"},"modern":"木匠、車匠各專一藝，養家糊口綽綽有餘；別生奢望想著轉行，惹來風波反而不安穩。這支籤講「守本業」的智慧：你現在做的事就是你的飯碗，深耕專精勝過見異思遷，知足就是平安。","categories":{"愛情婚姻":"對象宜找踏實相配的，不必高攀名門；門當戶對、平實過日子的感情最長久。","事業工作":"守住本行深耕就有飯吃，此刻不宜轉行或跳槽；貿然改變恐惹風波，把手上的專業磨精才是正路。","財運":"溫飽有餘、安穩小康；別羨慕別人賺快錢，守著本業的穩定收入，勿貪大利。","健康":"原本的醫師和療程就有效，照著做即可；別聽信偏方隨意換藥，安順靜養自然康復。","考試學業":"設定務實的目標、照自己的步調讀，穩穩就有成果；別好高騖遠亂換讀書方法。","訴訟糾紛":"能不爭就不爭，硬碰硬只會惹來風波；退一步協商了事，平安最值錢。","失物行人":"失物雖能尋回，過程難免懊惱，記取教訓即可；遠方的人在外安好，一時還不會回來，不必催。"}},
  {"id":91,"name":"","level":"中中","poem":["分明壹樹牡丹花","正欲開時豔若霞","忽遇狂風頃刻至","摧殘技葉萎泥沙"],"traditional":"","official":{"功名":"好夢將成，忽然驚醒","行人":"音信要通，無知沉絕","婚姻":"若圖眼前，恐無長久","官司":"要求長勝，反受禍殃","丁口":"好景不長，人丁有損","生意":"鏡花水月，事事皆空","疾病":"烏啼月落，燈燼香消","出行":"關山險阻，烟霧迷茫","失物":"物已消化，不用追求","田畜":"莫誇繁盛，恐有天災"},"modern":"一樹牡丹正要盛開、豔麗如霞，忽然狂風襲來，頃刻間枝葉摧折、委落泥沙。這支籤警示「好事多磨、盛極防變」：越是快到手的事越不能大意，凡事備好退路、見好就收，才不會功虧一簣。","categories":{"愛情婚姻":"眼前的熱烈未必長久，只圖一時激情恐難走遠；感情要經營在日常，別把話說滿、把未來押在浪漫上。","事業工作":"好夢將成忽然驚醒——快談成的案子、快到手的升遷都可能生變；合約沒簽定前別鬆懈，備妥備案。","財運":"帳面上的獲利如鏡花水月，沒入袋都不算數；勿投機、勿預支未來的錢，落袋為安。","健康":"身體狀況不可輕忽，小症狀可能急轉直下；及早檢查治療、留意變化，把握黃金時間就有轉圜。","考試學業":"勝券在握時最容易失手；越到最後越要穩住，防範臨場突發狀況，答完多檢查一遍。","訴訟糾紛":"貪求全勝反招禍殃；情勢對你有利時正是收手的時機，見好就收、及早和解。","失物行人":"失物已經流轉他處，追不回來就放下吧；遠方的人音訊沉寂，短期難有消息，先安頓好自己。"}},
  {"id":92,"name":"","level":"中","poem":["萬事無如忍最宜","勸君三覆細尋思","逢人切莫輕唐突","須學留侯進履時"],"traditional":"","official":{"功名":"謹慎待時，還宜早退","行人":"音信遲遲，何須性急","婚姻":"緩圖可就，急躁難成","官司":"退讓三分，可保無事","丁口":"安祥守己，家和事興","生意":"安心忍耐，自得便宜","疾病":"謹慎調和，切忌生氣","出行":"步步容忍，謙和有益","失物":"得失無常，何須煩腦","田畜":"勿貪小利，徒自勤勞"},"modern":"萬事沒有比忍耐更合宜的了，勸你凡事再三思量；待人切莫輕率唐突，要學張良為老人拾鞋進履，能屈能伸終成大器。這支籤的功課就一個字——忍：沉住氣、放低姿態、等對時機，眼前吃點小虧，日後都是福。","categories":{"愛情婚姻":"感情緩緩經營才有結果，急躁逼婚逼表態反而壞事；多點耐心與體諒，水到自然渠成。","事業工作":"此刻宜謹慎蹲低、養精蓄銳，不搶功不出頭；鋒芒先收起來，等到對的時機再一展身手。","財運":"安心忍耐自有便宜可得；別為小利躁進，也別跟人爭搶眼前那點好處，穩住反而賺得多。","健康":"最忌動怒生氣，情緒起伏最傷身；心平氣和、細心調養，健康自然回穩。","考試學業":"沉住氣按計畫準備，不跟人比進度；戒浮躁、多演練，臨場冷靜就是你的優勢。","訴訟糾紛":"退讓三分可保無事；口舌之爭忍下來，主動釋出善意和解，是損失最小的解法。","失物行人":"得失本無常，掉了就別再懊惱，該回來的自會回來；遠方的人消息慢些，不必性急，安心等候。"}},
  {"id":93,"name":"","level":"中中","poem":["泰華峯巔覓住家","果然地位迥堪誇","豈知歷盡登臨苦","方占山頭一片霞"],"traditional":"","official":{"功名":"縱得光輝，彩雲易散","行人":"事多艱阻，音信虛無","婚姻":"事無實際，妻家難靠","官司":"休誇依靠，得少失多","丁口":"不肯自卑，虛花難久","生意":"費盡心機，沾光有限","疾病":"竭力調治，安亦偶然","出行":"跋涉艱難，知音甚少","失物":"費心尋覓，亦難全歸","田畜":"雞黍寥落，其利甚微"},"modern":"在泰山華山的峰頂安家，位置確實高得令人稱羨；可誰知道一路攀登吃盡苦頭，到頭來只換得山頭一片晚霞。這支籤提醒你算算「值不值得」：目標雖風光，投入的心力與回報恐不成比例；調低期望、務實評估，別為了面子苦撐。","categories":{"愛情婚姻":"別指望靠對方的家世條件過日子，看起來風光的依靠未必實在；感情要建立在兩人實際的相處上。","事業工作":"費盡心機、沾光有限——投入很多但回報不成比例；先衡量成本效益，別為了頭銜或面子硬撐。","財運":"利潤微薄，賺的是辛苦錢；投入前算清楚成本，小額經營即可，別加碼追高。","健康":"調養要有長期抗戰的心理準備，難求速效；與其四處求偏方，不如穩定配合治療、耐心養好底子。","考試學業":"就算考出好成績，不持續耕耘也難維持；把眼光放長遠，實力累積比一時光彩重要。","訴訟糾紛":"別誇口自己有靠山，打下去得少失多；就算贏了也不划算，能和解就和解。","失物行人":"費心尋找也難全數找回，尋回多少算多少；遠方的人路途艱阻，音訊虛渺，需要多點耐心。"}},
  {"id":94,"name":"","level":"中下","poem":["昔年漁夫入桃源","雞黍相留笑語喧","今日再來無覓處","皆因福薄與緣慳"],"traditional":"","official":{"功名":"初年得志，晚運蕭條","行人":"水遠山長，相逢不易","婚姻":"前緣已盡，後會難期","官司":"前順後逆，事多不濟","丁口":"瞻望門閭，事多蕭條","生意":"起手得利，恐少收成","疾病":"小癒當慎，復病難痊","出行":"不須再往，只恐空歸","失物":"已無覓處，何必追尋","田畜":"田園荒落，桑拓蕭條"},"modern":"當年漁夫誤入桃花源，主人殺雞煮飯、笑語款待；今日再訪卻遍尋不著，只因福分薄、緣分淺。這支籤說的是「舊夢難重溫」：過去的美好機遇回不去了，別執著於重來一次；把眼光放向前方，另闢新局才有出路。","categories":{"愛情婚姻":"前緣已盡，逝去的感情勉強挽回也難如當初；與其苦守回憶，不如好好告別，把心整理好迎接新的緣分。","事業工作":"早年得意的方法如今未必管用，別想複製過去的成功；見好就收、及時轉型，另找新舞台。","財運":"起頭有賺、收尾難豐；有獲利就及早落袋，別想著回頭加碼重演上一次的行情。","健康":"小癒之後最要謹慎，一旦復發就難治了；痊癒前別急著恢復操勞，把療程走完、根本養好。","考試學業":"別靠過去的好成績吃老本，題型和程度都變了；歸零心態重新踏實準備，才有勝算。","訴訟糾紛":"前段順利、後段轉逆；趁情勢還沒惡化早點收手和解，拖下去多半不濟。","失物行人":"失物已無處可尋，就別再追了，放下反而輕鬆；遠方的人山高水長，短期內相逢不易。"}},
  {"id":95,"name":"","level":"中上","poem":["墻圍竹木稻盈田","雞犬桑麻境境徧","完卻官糧無別事","太平世界一神仙"],"traditional":"","official":{"功名":"福自天成，一生富貴","行人":"桃源樂境，漁人自來","婚姻":"家室安寧，一生穩足","官司":"天相吉人，官事順遂","丁口":"家門清吉，人口平安","生意":"隨分經營，一生財旺","疾病":"保合太和，身體康泰","出行":"一路平穩，諸事順利","失物":"不出門庭，何愁損失","田畜":"田財進益，六畜豐盛"},"modern":"牆邊竹木成蔭、稻穀滿田，雞犬桑麻處處安詳；繳完該繳的稅糧就沒別的事，太平歲月裡活得像神仙。這支籤畫的是安居樂業的好光景：本分做事、按時盡義務，日子自然平順富足；記得惜福，平安就是最大的福氣。","categories":{"愛情婚姻":"家室安寧、一生穩足；這是能安穩過一輩子的緣分，用心經營柴米油鹽的日常，幸福就在其中。","事業工作":"不必大起大落，守好本分、按部就班，就能穩定向上；把該盡的責任做好，自然無事一身輕。","財運":"隨分經營、一生財旺；不必冒險逐利，穩穩的收入細水長流，該繳該付的別拖欠，財務自然健康。","健康":"身心平和、體況康泰；維持規律的生活步調就是最好的保養，不必多慮。","考試學業":"福自天成，考運平順；照平常的節奏準備即可，不必焦慮，穩穩發揮就有好結果。","訴訟糾紛":"吉人天相，官事順遂；照規矩據實以對，事情會平和落幕。","失物行人":"失物多半沒離開家門，屋裡仔細找找就有；遠方的人自己會回來，安心等候便是。"}},
  {"id":96,"name":"","level":"中下","poem":["到處生財人莫知","何須奢望遠求之","壹兩黃金四兩福","無如命運本差池"],"traditional":"","official":{"功名":"福分有限，到底難成","行人":"阻隔山河，參差難見","婚姻":"逆水行舟，事終有阻","官司":"私不勝理，難免招災","丁口":"門戶冷淡，恐有小災","生意":"費盡心機，空勞無濟","疾病":"病重藥輕，難收功效","出行":"命運不濟，徒勞跋涉","失物":"捨近求遠，終歸難覓","田畜":"氣不旺見，孳息無成"},"modern":"其實到處都有生財的路，只是人不知道，何必奢望到遠方去求；常說一兩黃金要配四兩福氣，無奈眼下命運正走低。這支籤勸你「就近、放低、莫強求」：時運未濟時，遠大的計畫先擱著，守住眼前的小日子，把福氣慢慢養回來。","categories":{"愛情婚姻":"感情像逆水行舟，推進得很吃力；別硬拉著對方往前，順其自然、先把自己過好，強求不來的就放寬心。","事業工作":"好高騖遠只會白費心機；遠方的大餅先別追，把眼前手上的小事做好，守住本分等運轉。","財運":"大財無緣、小財就近可得；別到處找發財門路，減少開銷、顧好現有收入才是正解。","健康":"有病重藥輕之象，拖著只會更難好；及早找對醫師正規治療，耐心配合，別輕忽小毛病。","考試學業":"這一回福分有限、恐難如願；但別灰心，把目標調得務實些、方法重新調整，下次再拚。","訴訟糾紛":"私情敵不過公理，想走偏門私了反而招災；理虧的部分早認早了，及時止損。","失物行人":"別捨近求遠，越找越遠越找不到，就在身邊近處翻找；遠方的人山河阻隔，一時難相見。"}},
  {"id":97,"name":"","level":"中","poem":["目今雖遇颶風狂","雞犬逢時免禍殃","依舊壹天晴色好","教君安穩樂徜徉"],"traditional":"","official":{"功名":"目前雖阻，後運亨通","行人":"若問行踪，須交酉戌","婚姻":"如逢酉戌，家道興隆","官司":"事多驚險，幸遇青天","丁口":"目下未安，秋冬平順","生意":"目下未利，且待小春","疾病":"先憂後善，終得平安","出行":"雖多險道，終能平安","失物":"小往大來，不必怨悔","田畜":"春夏平常，秋冬獲利"},"modern":"眼下雖然遇上狂烈的颶風，但雞犬逢時都能免於禍殃；風雨過後依舊是一片晴朗好天，教你安安穩穩、悠然自在。這支籤說「先險後安」：現在的難關看著嚇人，其實傷不到根本；沉住氣撐過去，秋後天自然放晴。","categories":{"愛情婚姻":"目前感情多風波，先別急著下結論；撐過這陣子，入秋之後（酉戌月前後）關係回穩，家道興隆。","事業工作":"眼前處處受阻是暫時的，後運亨通；此刻別亂動、顧好手上的事，風頭過了自有你的舞台。","財運":"目前不宜求財，且待秋冬；先守住現金度過這段，小春之後財路轉旺，再出手不遲。","健康":"先憂後喜，現在的病痛雖折騰，終能平安痊癒；安心治療，別被一時的不適嚇到。","考試學業":"近期考運受阻，別因一次失常否定自己；持續準備，秋冬之後運勢轉強，翻身有望。","訴訟糾紛":"過程驚險但有貴人青天主持公道；穩住陣腳據實陳述，最終有驚無險。","失物行人":"失小得大，掉了的就別懊悔，後面有更好的補回來；遠方的人要到秋天（酉戌月）才有消息，耐心等。"}},
  {"id":98,"name":"","level":"上","poem":["榮華富貴爵巍峨","忠孝之人感太和","不遇風波無患難","元亨利貞致福多"],"traditional":"","official":{"功名":"富貴天生，功名得志","行人":"好音頻來，相逢不遠","婚姻":"夫榮子貴，一世亨通","官司":"吉人天相，諸事稱心","丁口":"迎祥集福，人口平安","生意":"貨物生財，安穩得利","疾病":"不必憂疑，即得痊癒","出行":"一路平安，無往不利","失物":"一生穩足，自無破失","田畜":"田園豐登，六畜俱亨"},"modern":"榮華富貴、爵位巍峨，是忠孝之人感召的祥和之氣；不遇風波、沒有患難，元亨利貞、福澤綿長。這支籤說福氣來自德行：你行得正、待人厚道，好運自然跟著來；繼續持守正道，富貴平安都水到渠成。","categories":{"愛情婚姻":"夫榮子貴、一世亨通；彼此以誠相待、孝親持家，這段姻緣穩固又有福氣，放心走下去。","事業工作":"富貴天生、功名得志；憑實力和正派作風就能步步高升，不必走捷徑，好名聲就是你的護身符。","財運":"貨暢其流、安穩得利；正正當當經營就有豐厚回報，財路平順，不必冒險。","健康":"不必憂疑，小恙很快痊癒；身心安泰，保持目前的生活步調即可。","考試學業":"功名得志之籤，考運極佳；平日的累積會如實反映在成績上，安心應考。","訴訟糾紛":"吉人天相、諸事稱心；行得正坐得端，是非自然分明，結果會如你所願。","失物行人":"運勢穩足，少有破財失物之虞，遺失的東西多能找回；遠方的人好消息頻傳，相逢就在不遠。"}},
  {"id":99,"name":"","level":"上上","poem":["簷前忽聽鵲聲喧","知有佳音到汝門","官職遷陞行客至","百凡順遂不須論"],"traditional":"","official":{"功名":"喜音重重，功名顯達","行人":"鵲報好音，行人即至","婚姻":"夫妻和順，財喜臨門","官司":"貴人有緣，諸事順遂","丁口":"家室盈寧，芝蘭茂盛","生意":"經營順利，發財添喜","疾病":"福星拱照，悔吝自清","出行":"出門順利，滿載而歸","失物":"偶有疏忽，尋而復得","田畜":"門閭增喜，物阜財豐"},"modern":"屋簷前忽然聽見喜鵲喧鬧，就知道有好消息要進家門；官職高升、遠客到來，百事順遂不必多說。這是大吉之籤，喜事將接連報到；放手去做想做的事，同時記得與身邊的人分享福氣，好運會更長久。","categories":{"愛情婚姻":"夫妻和順、財喜臨門；感情正處在最好的時候，論嫁娶、添丁都是吉兆，可以放心規劃。","事業工作":"功名顯達、升遷有望；喜訊重重報到，爭取的職位和機會大膽去要，正是揚眉吐氣的時候。","財運":"經營順利、發財添喜；財路暢旺，投入的心血都有回報，順勢而為即可。","健康":"福星拱照，病痛自然消散；小毛病不必掛心，身體很快恢復輕快。","考試學業":"喜鵲報喜、金榜題名之象；考運大開，安心發揮實力，會有令人開心的結果。","訴訟糾紛":"有貴人相助，諸事順遂；糾紛能圓滿化解，甚至因此結識助力，不必憂心。","失物行人":"東西只是一時疏忽放錯地方，找一找就會出現；遠方的人即將到來，好消息已在路上。"}},
  {"id":100,"name":"","level":"上上","poem":["此籤壹百最難逢","氣象巍巍實不同","識得謙冲持滿意","萬人頭上逞英雄"],"traditional":"","official":{"功名":"履滿思謙，崇高永泰","行人":"坐久忽逢，遂心滿意","婚姻":"白頭偕老，吉祥如意","官司":"能以理勝，自占上風","丁口":"春色盈門，百事如意","生意":"所向得利，加人一籌","疾病":"善能調養，後福無量","出行":"順風揚帆，無往不利","失物":"不必張揚，自可尋獲","田畜":"時泰年豐，百產如意"},"modern":"這第一百籤最是難逢，氣象巍峨、格局非凡；但要懂得謙沖自持、滿而不溢，才能在萬人之上成就英雄事業。這是百籤之首的大吉籤，什麼都站在最高點；唯一的功課是「謙」：越是圓滿越要低調惜福，謙虛能讓這份好運走得長遠。","categories":{"愛情婚姻":"白頭偕老、吉祥如意；這是能相守一生的好姻緣，得意時更要珍惜對方、互相尊重，幸福自然長久。","事業工作":"所向得利、勝人一籌；正站在事業高峰，放手施展之餘記得謙沖待人，不居功不張揚，地位才坐得穩。","財運":"財源廣進、樣樣得利；豐收之時懂得節制與分享，別因滿手好牌而躁進，富貴方能長保。","健康":"體況佳，善加調養則後福無量；別仗著身體好就透支，維持節度，健康才是萬事的本錢。","考試學業":"登峰造極之象，考運極盛；保持謙虛不輕敵，穩穩發揮，名列前茅可期。","訴訟糾紛":"以理服人、自佔上風；你這方佔理又有優勢，得理也要饒人，圓滿收場最漂亮。","失物行人":"失物不必張揚聲張，靜靜找自然尋獲；久候的人會忽然出現，遂心滿意，安心等候。"}},
]
